def run_text_process(
    args: list[str], *, check: bool = False, **kwargs: object
) -> subprocess.CompletedProcess[str]:
    """Run subprocess with robust UTF-8 decoding for test helpers."""
    return subprocess.run(
        args,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=check,
        **kwargs,
    )


def parse_validate_py_compile_entries(makefile_path: Path) -> list[str]:
    entries: list[str] = []
    in_validate = False
    in_py_compile = False
    for raw_line in makefile_path.read_text(encoding="utf-8").splitlines():
        if raw_line.startswith("validate:"):
            in_validate = True
            in_py_compile = False
            continue
        if not in_validate:
            continue
        if raw_line.startswith("\t$(PYTHON) -m py_compile"):
            in_py_compile = True
            continue
        if raw_line.startswith("\tbash -n"):
            break
        if not in_py_compile:
            continue
        token = raw_line.strip().rstrip("\\").strip()
        if token.endswith(".py"):
            entries.append(token)
    return entries


def parse_validate_bash_syntax_entries(makefile_path: Path) -> list[str]:
    entries: list[str] = []
    in_validate = False
    in_bash_check = False
    for raw_line in makefile_path.read_text(encoding="utf-8").splitlines():
        if raw_line.startswith("validate:"):
            in_validate = True
            in_bash_check = False
            continue
        if not in_validate:
            continue
        if raw_line.startswith("\tbash -n"):
            in_bash_check = True
            continue
        if raw_line.startswith("\t$(MAKE) check-ci-scopes"):
            break
        if not in_bash_check:
            continue
        token = raw_line.strip().rstrip("\\").strip()
        if token.endswith(".sh"):
            entries.append(token)
    return entries


def parse_github_output_entries(path: Path) -> list[tuple[str, str]]:
    entries: list[tuple[str, str]] = []
    lines = path.read_text(encoding="utf-8").splitlines()
    idx = 0
    while idx < len(lines):
        line = lines[idx]
        if "<<" in line:
            key, marker = line.split("<<", 1)
            idx += 1
            payload_lines: list[str] = []
            while idx < len(lines) and lines[idx] != marker:
                payload_lines.append(lines[idx])
                idx += 1
            if idx >= len(lines):
                raise AssertionError(f"missing heredoc marker terminator for key: {key}")
            entries.append((key, "\n".join(payload_lines)))
            idx += 1
            continue
        key, sep, value = line.partition("=")
        if not sep:
            raise AssertionError(f"invalid GitHub output line: {line!r}")
        entries.append((key, value))
        idx += 1
    return entries


def run_script(script: Path, *args: str, expected_rc: int = 0) -> subprocess.CompletedProcess[str]:
    proc = run_text_process(
        [PYTHON, str(script), *args],
        capture_output=True,
    )
    if proc.returncode != expected_rc:
        raise AssertionError(
            f"unexpected return code for {script.name}: got={proc.returncode} expected={expected_rc}\n"
            f"stdout:\n{proc.stdout}\n"
            f"stderr:\n{proc.stderr}"
        )
    return proc


def step_summary_env(step_summary_path: Path, *, fallback_to_github: bool = False) -> dict[str, str]:
    env = dict(os.environ)
    if fallback_to_github:
        env["STEP_SUMMARY_FILE"] = "   "
        env["GITHUB_STEP_SUMMARY"] = str(step_summary_path)
        return env
    env["STEP_SUMMARY_FILE"] = str(step_summary_path)
    return env


def assert_step_summary_ci_error(
    testcase: unittest.TestCase,
    *,
    step_summary_path: Path,
    source: str,
    phase: str,
    message_substring: str,
) -> None:
    testcase.assertTrue(step_summary_path.exists())
    summary_text = step_summary_path.read_text(encoding="utf-8")
    testcase.assertIn("## E2E CI Error", summary_text)
    testcase.assertIn(f"- source: `{source}`", summary_text)
    testcase.assertIn(f"- phase: `{phase}`", summary_text)
    testcase.assertIn(message_substring, summary_text)


