def assert_github_output_heredoc_layout(
    testcase: unittest.TestCase,
    *,
    output_path: Path,
    key: str,
    expected_payload_lines: list[str],
) -> None:
    testcase.assertTrue(output_path.exists())
    lines = output_path.read_text(encoding="utf-8").splitlines()
    testcase.assertEqual(len(lines), len(expected_payload_lines) + 2)
    testcase.assertTrue(lines[0].startswith(f"{key}<<CI_EOF_"))
    marker = lines[0].split("<<", 1)[1]
    for idx, expected in enumerate(expected_payload_lines, start=1):
        testcase.assertEqual(lines[idx], expected)
    testcase.assertEqual(lines[-1], marker)


def extract_first_call_expression(source_text: str, callee_name: str) -> str:
    anchor = f"{callee_name}("
    call_start = source_text.find(anchor)
    if call_start < 0:
        return ""
    open_idx = call_start + len(callee_name)
    depth = 0
    for pos in range(open_idx, len(source_text)):
        ch = source_text[pos]
        if ch == "(":
            depth += 1
            continue
        if ch != ")":
            continue
        depth -= 1
        if depth == 0:
            return source_text[call_start : pos + 1]
    return ""


def git_run(repo_dir: Path, *args: str) -> subprocess.CompletedProcess[str]:
    return run_text_process(
        ["git", *args],
        cwd=repo_dir,
        capture_output=True,
        check=True,
    )


def git_commit_all(repo_dir: Path, message: str) -> str:
    git_run(repo_dir, "add", ".")
    git_run(
        repo_dir,
        "-c",
        "user.name=CI",
        "-c",
        "user.email=ci@example.invalid",
        "commit",
        "-m",
        message,
    )
    return git_run(repo_dir, "rev-parse", "HEAD").stdout.strip()


class LoadCiMatrixTests(unittest.TestCase):
    def test_load_all_profiles(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            profiles_path = tmp_path / "profiles.json"
            profiles_path.write_text(
                json.dumps(
                    {
                        "profiles": [
                            {
                                "profile_id": "sds_v0_1_0",
                                "default_batch_spec": "batch_v1.json",
                                "default_sds_versions": "sds_v0.1.0",
                            },
                            {
                                "profile_id": "sds_v0_2_0",
                                "default_batch_spec": "batch_v2.json",
                                "default_sds_versions": "sds_v0.2.0",
                            },
                        ]
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            proc = run_script(
                PROTOTYPE_DIR / "load_ci_matrix.py",
                "--profiles-file",
                str(profiles_path),
            )
            matrix = read_json_text(self, text=proc.stdout)
            self.assertEqual(len(matrix["include"]), 2)
            self.assertEqual(matrix["include"][0]["profile_id"], "sds_v0_1_0")

    def test_filter_profiles(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            profiles_path = tmp_path / "profiles.json"
            profiles_path.write_text(
                json.dumps(
                    {
                        "profiles": [
                            {
                                "profile_id": "a",
                                "default_batch_spec": "a.json",
                                "default_sds_versions": "sds_a",
                            },
                            {
                                "profile_id": "b",
                                "default_batch_spec": "b.json",
                                "default_sds_versions": "sds_b",
                            },
                        ]
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            proc = run_script(
                PROTOTYPE_DIR / "load_ci_matrix.py",
                "--profiles-file",
                str(profiles_path),
                "--profile-id",
                "b",
            )
            matrix = read_json_text(self, text=proc.stdout)
            self.assertEqual(len(matrix["include"]), 1)
            self.assertEqual(matrix["include"][0]["default_batch_spec"], "b.json")

            error_proc = run_script(
                PROTOTYPE_DIR / "load_ci_matrix.py",
                "--profiles-file",
                str(profiles_path),
                "--profile-id",
                "does-not-exist",
                expected_rc=1,
            )
            self.assertIn("[error] load_ci_matrix.py:", error_proc.stderr)
            self.assertIn("no CI matrix profiles selected", error_proc.stderr)
            self.assertNotIn("Traceback", error_proc.stderr)

