class ResolveRuntimeMatrixProfileIdsTests(unittest.TestCase):
    def test_filters_profiles_by_runtime_and_keeps_generic_entries(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            profiles_path = tmp_path / "runtime_profiles.json"
            profiles_path.write_text(
                json.dumps(
                    {
                        "profiles": [
                            {"profile_id": "runtime_awsim", "sim_runtime": "awsim"},
                            {"profile_id": "runtime_carla", "sim_runtime": "carla"},
                            {"profile_id": "runtime_generic"},
                        ]
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            proc = run_script(
                PROTOTYPE_DIR / "resolve_runtime_matrix_profile_ids.py",
                "--profiles-file",
                str(profiles_path),
                "--profile-ids-csv",
                "runtime_awsim,runtime_generic,runtime_carla,unknown_profile",
                "--sim-runtime",
                "awsim",
            )
            self.assertEqual(
                proc.stdout.strip(),
                "runtime_awsim,runtime_generic,unknown_profile",
            )

    def test_empty_profile_ids_csv_uses_runtime_default(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            profiles_path = tmp_path / "runtime_profiles.json"
            profiles_path.write_text(json.dumps({"profiles": []}) + "\n", encoding="utf-8")
            proc = run_script(
                PROTOTYPE_DIR / "resolve_runtime_matrix_profile_ids.py",
                "--profiles-file",
                str(profiles_path),
                "--sim-runtime",
                "carla",
            )
            self.assertEqual(proc.stdout.strip(), "runtime_carla_smoke_v0")

    def test_invalid_profile_runtime_token_fails_with_prefixed_error(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            profiles_path = tmp_path / "runtime_profiles.json"
            profiles_path.write_text(
                json.dumps(
                    {
                        "profiles": [
                            {"profile_id": "runtime_bad", "sim_runtime": "invalid_runtime"}
                        ]
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            proc = run_script(
                PROTOTYPE_DIR / "resolve_runtime_matrix_profile_ids.py",
                "--profiles-file",
                str(profiles_path),
                "--sim-runtime",
                "carla",
                expected_rc=1,
            )
            self.assertIn("[error] resolve_runtime_matrix_profile_ids.py:", proc.stderr)
            self.assertIn(
                "invalid profiles[0].sim_runtime: expected one of none|awsim|carla, got: invalid_runtime",
                proc.stderr,
            )
            self.assertNotIn("Traceback", proc.stderr)


class GenerateSdsBatchesTests(unittest.TestCase):
    def test_generates_specs_and_profiles_from_version_list(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            catalog_manifest = tmp_path / "catalog_manifest.json"
            catalog_manifest.write_text(json.dumps({"scenarios": [{"scenario_file": "s1.json"}]}) + "\n", encoding="utf-8")

            fake_generator = tmp_path / "fake_generator.py"
            fake_generator.write_text(
                "import json\n"
                "import sys\n"
                "from pathlib import Path\n"
                "\n"
                "args = sys.argv[1:]\n"
                "def get(flag):\n"
                "    idx = args.index(flag)\n"
                "    return args[idx + 1]\n"
                "out_path = Path(get('--out')).resolve()\n"
                "out_path.parent.mkdir(parents=True, exist_ok=True)\n"
                "payload = {\n"
                "    'batch_id': get('--batch-id'),\n"
                "    'sds_version': get('--sds-version'),\n"
                "    'run_id_prefix': get('--run-id-prefix'),\n"
                "    'seed_base': int(get('--seed-base')),\n"
                "}\n"
                "out_path.write_text(json.dumps(payload) + '\\n', encoding='utf-8')\n"
                "print(f'[ok] out={out_path}')\n",
                encoding="utf-8",
            )

            out_dir = tmp_path / "generated_specs"
            profiles_out = tmp_path / "matrix_profiles.json"
            proc = run_script(
                PROTOTYPE_DIR / "generate_sds_batches.py",
                "--catalog-manifest",
                str(catalog_manifest),
                "--versions",
                "sds_v0.1.0 sds_v0.2.0 sds_v0.2.0",
                "--out-dir",
                str(out_dir),
                "--generator",
                str(fake_generator),
                "--seed-base",
                "500",
                "--seed-version-stride",
                "100",
                "--profiles-out",
                str(profiles_out),
            )

            self.assertIn("[ok] generated_specs=2", proc.stdout)
            self.assertIn("[ok] profile_count=2", proc.stdout)

            first_spec = out_dir / "batch_regression_highway_sds_v0.1.0.json"
            second_spec = out_dir / "batch_regression_highway_sds_v0.2.0.json"
            self.assertTrue(first_spec.exists())
            self.assertTrue(second_spec.exists())

            first_payload = read_json_file(self, file_path=first_spec)
            second_payload = read_json_file(self, file_path=second_spec)
            self.assertEqual(first_payload["batch_id"], "BATCH_REG_HWY_SDS_V0_1_0_0001")
            self.assertEqual(second_payload["batch_id"], "BATCH_REG_HWY_SDS_V0_2_0_0001")
            self.assertEqual(first_payload["run_id_prefix"], "RUN_RG_SDS_V0_1_0")
            self.assertEqual(second_payload["run_id_prefix"], "RUN_RG_SDS_V0_2_0")
            self.assertEqual(first_payload["seed_base"], 500)
            self.assertEqual(second_payload["seed_base"], 600)

            profiles_payload = read_json_file(self, file_path=profiles_out)
            profiles = profiles_payload.get("profiles", [])
            self.assertEqual(len(profiles), 2)
            self.assertEqual(profiles[0]["profile_id"], "sds_v0_1_0")
            self.assertEqual(profiles[0]["default_sds_versions"], "sds_v0.1.0")
            self.assertEqual(profiles[1]["profile_id"], "sds_v0_2_0")
            self.assertEqual(profiles[1]["default_sds_versions"], "sds_v0.2.0")

