class ScenarioVariantGenerationTests(unittest.TestCase):
    def test_full_cartesian_generation_is_stable(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            logical_path = tmp_path / "logical_scenarios.json"
            logical_path.write_text(
                json.dumps(
                    {
                        "logical_scenarios": [
                            {
                                "scenario_id": "scn_cut_in",
                                "parameters": {
                                    "ego_speed_kph": [60, 80],
                                    "gap_sec": [1.0, 1.5],
                                },
                            }
                        ]
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            out_path = tmp_path / "generated_variants.json"
            proc = run_script(
                PROTOTYPE_DIR / "../../P_Validation-Tooling-MVP/prototype/generate_scenario_variants.py",
                "--logical-scenarios",
                str(logical_path),
                "--out",
                str(out_path),
                "--sampling",
                "full",
            )
            self.assertIn("[ok] logical_scenario_count=1", proc.stdout)
            self.assertIn("[ok] generated_variant_count=4", proc.stdout)

            first_payload = read_json_file(self, file_path=out_path)
            first_variants = first_payload.get("variants", [])
            self.assertEqual(first_payload.get("scenario_count"), 1)
            self.assertEqual(first_payload.get("variant_count"), 4)
            self.assertEqual(
                first_variants,
                [
                    {
                        "scenario_id": "scn_cut_in_0001",
                        "logical_scenario_id": "scn_cut_in",
                        "parameters": {"ego_speed_kph": 60, "gap_sec": 1.0},
                    },
                    {
                        "scenario_id": "scn_cut_in_0002",
                        "logical_scenario_id": "scn_cut_in",
                        "parameters": {"ego_speed_kph": 60, "gap_sec": 1.5},
                    },
                    {
                        "scenario_id": "scn_cut_in_0003",
                        "logical_scenario_id": "scn_cut_in",
                        "parameters": {"ego_speed_kph": 80, "gap_sec": 1.0},
                    },
                    {
                        "scenario_id": "scn_cut_in_0004",
                        "logical_scenario_id": "scn_cut_in",
                        "parameters": {"ego_speed_kph": 80, "gap_sec": 1.5},
                    },
                ],
            )

            run_script(
                PROTOTYPE_DIR / "../../P_Validation-Tooling-MVP/prototype/generate_scenario_variants.py",
                "--logical-scenarios",
                str(logical_path),
                "--out",
                str(out_path),
                "--sampling",
                "full",
            )
            second_payload = read_json_file(self, file_path=out_path)
            self.assertEqual(first_variants, second_payload.get("variants", []))

