class SensorSimBridgeTests(unittest.TestCase):
    def test_generates_sorted_sensor_frames_from_rig(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            world_state = tmp_path / "world_state.json"
            sensor_rig = tmp_path / "sensor_rig.json"
            out_path = tmp_path / "sensor_frames.json"

            world_state.write_text(
                json.dumps(
                    {
                        "world_state_schema_version": "world_state_v0",
                        "frame_timestamp": "2026-02-27T03:00:00Z",
                        "actors": [{"actor_id": "ego"}, {"actor_id": "npc_001"}],
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            sensor_rig.write_text(
                json.dumps(
                    {
                        "rig_schema_version": "sensor_rig_v0",
                        "sensors": [
                            {"sensor_id": "radar_front", "sensor_type": "radar"},
                            {
                                "sensor_id": "lidar_top",
                                "sensor_type": "lidar",
                                "points_per_actor": 30,
                            },
                            {"sensor_id": "camera_front", "sensor_type": "camera"},
                        ],
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            proc = run_script(
                PROTOTYPE_DIR / "../../P_Sim-Engine/prototype/sensor_sim_bridge.py",
                "--world-state",
                str(world_state),
                "--sensor-rig",
                str(sensor_rig),
                "--out",
                str(out_path),
            )
            self.assertIn("[ok] sensor_frame_count=3", proc.stdout)
            self.assertTrue(out_path.exists())

            payload = read_json_file(self, file_path=out_path)
            frames = payload.get("frames", [])
            self.assertEqual(payload.get("frame_count"), 3)
            self.assertEqual([frame["sensor_id"] for frame in frames], ["camera_front", "lidar_top", "radar_front"])
            self.assertEqual(frames[0]["payload"]["modality"], "camera")
            self.assertEqual(frames[1]["payload"]["point_count"], 60)
            self.assertEqual(frames[2]["payload"]["modality"], "radar")

    def test_high_fidelity_tier_writes_fidelity_metadata(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            world_state = tmp_path / "world_state.json"
