    def test_writes_traffic_profile_metadata_to_summary(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            scenario_path = tmp_path / "scenario.json"
            scenario_path.write_text(
                json.dumps(
                    {
                        "scenario_schema_version": "scenario_definition_v0",
                        "scenario_id": "scenario_traffic_profile_001",
                        "duration_sec": 2.0,
                        "dt_sec": 0.1,
                        "ego": {"actor_id": "ego", "position_m": 0.0, "speed_mps": 10.0},
                        "npcs": [{"actor_id": "npc_1", "position_m": 40.0, "speed_mps": 8.0}],
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            runs_root = tmp_path / "runs"
            run_id = "RUN_CORE_TRAFFIC_PROFILE_001"
            run_script(
                PROTOTYPE_DIR / "../../P_Sim-Engine/prototype/core_sim_runner.py",
                "--scenario",
                str(scenario_path),
                "--run-id",
                run_id,
                "--out",
                str(runs_root),
                "--traffic-profile-id",
                "sumo_highway_aggressive_v0",
                "--traffic-actor-pattern-id",
                "sumo_dense_aggressive_v0",
                "--traffic-npc-speed-scale",
                "1.2",
                "--traffic-npc-speed-jitter-mps",
                "0.6",
            )

            summary_path = runs_root / run_id / "summary.json"
