class MapToolsetConverterTests(unittest.TestCase):
    def test_roundtrip_simple_and_canonical_map_formats(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            simple_map = tmp_path / "simple_map.json"
            simple_map.write_text(
                json.dumps(
                    {
                        "map_schema_version": "simple_map_v0",
                        "map_id": "map_roundtrip_001",
                        "roads": [
                            {
                                "road_id": "lane_a",
                                "lane_type": "driving",
                                "speed_limit_kph": 70,
                                "centerline": [[0, 0], [20, 0], [40, 2]],
                                "predecessor_lane_ids": [],
                                "successor_lane_ids": ["lane_b"],
                            },
                            {
                                "road_id": "lane_b",
                                "lane_type": "driving",
                                "speed_limit_kph": 70,
                                "centerline": [[40, 2], [60, 3], [80, 4]],
                                "predecessor_lane_ids": ["lane_a"],
                                "successor_lane_ids": [],
                            },
                        ],
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            canonical_map = tmp_path / "canonical_map.json"
            roundtrip_map = tmp_path / "roundtrip_map.json"

            run_script(
                PROTOTYPE_DIR / "../../P_Map-Toolset-MVP/prototype/convert_map_format.py",
                "--input",
                str(simple_map),
                "--to-format",
                "canonical",
                "--out",
                str(canonical_map),
            )
            run_script(
                PROTOTYPE_DIR / "../../P_Map-Toolset-MVP/prototype/convert_map_format.py",
                "--input",
                str(canonical_map),
                "--to-format",
                "simple",
                "--out",
                str(roundtrip_map),
            )

            canonical = read_json_file(self, file_path=canonical_map)
            roundtrip = read_json_file(self, file_path=roundtrip_map)
            self.assertEqual(canonical.get("map_schema_version"), "canonical_lane_graph_v0")
            self.assertEqual(roundtrip.get("map_schema_version"), "simple_map_v0")
            lanes = canonical.get("lanes", [])
            roads = roundtrip.get("roads", [])
            self.assertEqual(len(lanes), 2)
            self.assertEqual(len(roads), 2)
            self.assertEqual(roads[0]["road_id"], "lane_a")
            self.assertEqual(roads[0]["centerline"], [[0.0, 0.0], [20.0, 0.0], [40.0, 2.0]])
            self.assertEqual(roads[1]["predecessor_lane_ids"], ["lane_a"])

