    def test_resolves_runtime_bin_from_directory_and_makes_executable(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            launch_manifest_path = tmp_path / "sim_runtime_launch_manifest.json"
            out_path = tmp_path / "sim_runtime_probe_report.json"
            runtime_root = tmp_path / "carla_runtime"
            runtime_entry = runtime_root / "LinuxNoEditor" / "CarlaUE4.sh"
            runtime_entry.parent.mkdir(parents=True, exist_ok=True)
            runtime_entry.write_text(
                "#!/usr/bin/env bash\n"
                "if [ \"$1\" = \"--help\" ]; then\n"
                "  echo carla_help\n"
                "  exit 0\n"
                "fi\n"
                "exit 0\n",
                encoding="utf-8",
            )
            os.chmod(runtime_entry, 0o644)

            launch_manifest_path.write_text(
                json.dumps(
                    {
                        "sim_runtime_launch_manifest_schema_version": "sim_runtime_launch_manifest_v0",
                        "runtime": "carla",
                        "mode": "headless",
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            proc = run_script(
                PROTOTYPE_DIR / "../../P_Sim-Engine/prototype/sim_runtime_probe_runner.py",
                "--runtime",
                "carla",
                "--launch-manifest",
                str(launch_manifest_path),
                "--runtime-bin",
                str(runtime_root),
                "--execute-probe",
                "--require-availability",
                "--out",
                str(out_path),
            )
            self.assertIn("[ok] runtime=carla", proc.stdout)
            payload = read_json_file(self, file_path=out_path)
            self.assertTrue(payload.get("runtime_available"))
            self.assertTrue(payload.get("probe_executed"))
            self.assertEqual(int(payload.get("probe_returncode", -1)), 0)
            self.assertTrue(bool(payload.get("probe_returncode_acceptable")))
            self.assertEqual(
                str(payload.get("runtime_bin_resolution_strategy", "")).strip(),
                "directory_glob",
            )
            self.assertTrue(bool(payload.get("runtime_bin_made_executable")))
            resolved_bin = str(payload.get("runtime_bin_resolved", "")).strip()
            self.assertEqual(resolved_bin, str(runtime_entry.resolve()))
            self.assertTrue(os.access(resolved_bin, os.X_OK))
            candidates_checked = payload.get("runtime_bin_candidates_checked", [])
            self.assertIsInstance(candidates_checked, list)
            self.assertIn(resolved_bin, candidates_checked)

