class PrepareRuntimeAssetsTests(unittest.TestCase):
    def _write_tar_gz(self, *, root_dir: Path, tar_path: Path) -> None:
        with tarfile.open(tar_path, "w:gz") as archive:
            archive.add(root_dir, arcname=root_dir.name)

    def _sha256_file(self, *, file_path: Path) -> str:
        hasher = hashlib.sha256()
        with file_path.open("rb") as handle:
            while True:
                chunk = handle.read(1024 * 1024)
                if not chunk:
                    break
                hasher.update(chunk)
        return hasher.hexdigest()

    def test_prepares_runtime_assets_from_local_archives_and_emits_env(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            source_root = tmp_path / "sources"
