            packages_root = tmp_path / "packages"
            packages_root.mkdir(parents=True, exist_ok=True)

            carla_core_dir = source_root / "carla_core"
            (carla_core_dir / "CarlaUE4/Content/Carla/Maps").mkdir(parents=True, exist_ok=True)
            (carla_core_dir / "PythonAPI/examples").mkdir(parents=True, exist_ok=True)
            (carla_core_dir / "CarlaUE4.sh").write_text("#!/usr/bin/env bash\necho carla\n", encoding="utf-8")
            (carla_core_dir / "CarlaUE4/Content/Carla/Maps/Town01.umap").write_text("map", encoding="utf-8")
            (carla_core_dir / "PythonAPI/examples/example.py").write_text("print('ok')\n", encoding="utf-8")
            carla_core_archive = packages_root / "carla_core.tar.gz"
            self._write_tar_gz(root_dir=carla_core_dir, tar_path=carla_core_archive)

            carla_maps_dir = source_root / "carla_maps"
