            awsim_row = runtimes.get("awsim", {})
            self.assertIsInstance(awsim_row, dict)
            runtime_bin_resolved = str(awsim_row.get("runtime_bin_resolved", "")).strip()
            self.assertTrue(runtime_bin_resolved)
            host_platform = str(awsim_row.get("host_platform", "")).strip().lower()
            if host_platform.startswith("linux_"):
                self.assertTrue(runtime_bin_resolved.endswith("AWSIM.x86_64"))
            elif host_platform.startswith("darwin_"):
                self.assertIn("AWSIM.app/Contents/MacOS/", runtime_bin_resolved)
