            payload = read_json_file(self, file_path=resolved_out)
            self.assertEqual(str(payload.get("archive_sha256_mode", "")).strip(), "verify_only")
            assets = payload.get("assets", [])
            self.assertIsInstance(assets, list)
            self.assertEqual(len(assets), 1)
            asset_row = assets[0]
            self.assertIsInstance(asset_row, dict)
            self.assertEqual(str(asset_row.get("expected_sha256", "")).strip(), archive_sha256)
            self.assertEqual(str(asset_row.get("archive_sha256", "")).strip(), archive_sha256)
            self.assertTrue(bool(asset_row.get("archive_sha256_computed")))

