class AdpWorkflowTraceStubTests(unittest.TestCase):
    def test_builds_adp_workflow_trace_from_pipeline_manifest(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            pipeline_manifest = tmp_path / "pipeline_result.json"
            release_summary = tmp_path / "release.summary.json"
            out_path = tmp_path / "adp_workflow_trace.json"
            pipeline_manifest.write_text(
                json.dumps(
                    {
                        "release_id": "REL_ADP_TRACE_001",
                        "batch_id": "batch_adp_001",
                        "overall_result": "PASS",
                        "phase2_hooks": {"enabled": False},
                        "phase3_hooks": {"enabled": True},
                        "phase4_hooks": {"enabled": True},
                        "reports": [
                            {"sds_version": "sds_v0.1.0"},
                            {"sds_version": "sds_v0.2.0"},
                        ],
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            release_summary.write_text(
                json.dumps(
                    {
                        "release_id": "REL_ADP_TRACE_001_sds_v0.1.0",
                        "sds_version": "sds_v0.1.0",
                        "final_result": "PASS",
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            proc = run_script(
                PROTOTYPE_DIR / "adp_workflow_trace_stub.py",
                "--pipeline-manifest",
                str(pipeline_manifest),
                "--release-summary",
                str(release_summary),
                "--out",
                str(out_path),
            )
            self.assertIn("[ok] report_count=2", proc.stdout)
            self.assertIn("[ok] release_summary_count=1", proc.stdout)
            self.assertIn("[ok] responsibility_notice_count=0", proc.stdout)
            payload = read_json_file(self, file_path=out_path)
            self.assertEqual(payload.get("adp_workflow_trace_schema_version"), "adp_workflow_trace_v0")
            self.assertEqual(payload.get("release_id"), "REL_ADP_TRACE_001")
            self.assertEqual(payload.get("batch_id"), "batch_adp_001")
            self.assertEqual(payload.get("overall_result"), "PASS")
            self.assertEqual(payload.get("report_count"), 2)
            self.assertEqual(payload.get("sds_versions"), ["sds_v0.1.0", "sds_v0.2.0"])
            module_hooks = payload.get("module_hooks", {})
            self.assertFalse(bool(module_hooks.get("phase2_enabled")))
            self.assertTrue(bool(module_hooks.get("phase3_enabled")))
            self.assertTrue(bool(module_hooks.get("phase4_enabled")))
            user_responsibility = payload.get("user_responsibility", {})
            self.assertFalse(bool(user_responsibility.get("requires_ack")))
            self.assertEqual(user_responsibility.get("notice_count"), 0)
            self.assertEqual(user_responsibility.get("notices"), [])

