class Phase4ModuleLinkageCheckStubTests(unittest.TestCase):
    def _write_matrix(self, path: Path, *, adp_status: str = "PHASE4_IN_PROGRESS", copilot_status: str = "PHASE4_IN_PROGRESS") -> None:
        path.write_text(
            "\n".join(
                [
                    "# Matrix",
                    "",
                    "| Module | AppliedDocs Reference | Local Spec | Local Code Base | Parity Phase | Status | First Deliverable (DoD) |",
                    "|---|---|---|---|---|---|---|",
                    f"| `adp` | ref | spec | code | Phase-4 | {adp_status} | desc |",
                    f"| `copilot` | ref | spec | code | Phase-4 | {copilot_status} | desc |",
                    "",
                ]
            ),
            encoding="utf-8",
        )

    def _write_checklist(self, path: Path, *, adp_statuses: list[str], copilot_statuses: list[str]) -> None:
        def render_rows(rows: list[str]) -> list[str]:
            rendered: list[str] = []
            for index, status in enumerate(rows, start=1):
                rendered.append(f"| feature_{index} | evidence | {status} | verify |")
            return rendered

        lines: list[str] = [
            "# Checklist",
            "",
            "## adp",
            "",
            "| Feature | Local Evidence Path | Status | Verification Command |",
            "|---|---|---|---|",
            *render_rows(adp_statuses),
            "",
            "## copilot",
            "",
            "| Feature | Local Evidence Path | Status | Verification Command |",
            "|---|---|---|---|",
            *render_rows(copilot_statuses),
            "",
        ]
        path.write_text("\n".join(lines), encoding="utf-8")

    def _write_reference_map(
        self,
        path: Path,
        *,
        adp_refs: str = "`autowarefoundation/autoware`, `carla-simulator/carla`",
        copilot_refs: str = "`commaai/openpilot`, `carla-simulator/carla`",
        adp_pattern: str = "pattern",
        copilot_pattern: str = "pattern",
        adp_target: str = "target",
        copilot_target: str = "target",
        include_duplicate_adp_row: bool = False,
    ) -> None:
        lines: list[str] = [
            "# Phase-4 External Reference Map",
            "",
            "| Phase-4 Module | Priority | Primary References | Pattern to Extract | Local First Target |",
            "|---|---|---|---|---|",
            f"| `adp` | P1 | {adp_refs} | {adp_pattern} | {adp_target} |",
            f"| `copilot` | P1 | {copilot_refs} | {copilot_pattern} | {copilot_target} |",
        ]
        if include_duplicate_adp_row:
            lines.append("| `adp` | P1 | `autowarefoundation/autoware` | duplicate pattern | duplicate target |")
        lines.append("")
        path.write_text(
            "\n".join(lines),
            encoding="utf-8",
        )

    def test_validates_matrix_and_checklist_linkage(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            matrix_path = tmp_path / "STACK_MODULE_PARITY_MATRIX.md"
            checklist_path = tmp_path / "PHASE4_MODULE_PARITY_CHECKLIST.md"
            reference_map_path = tmp_path / "PHASE4_EXTERNAL_REFERENCE_MAP.md"
            out_path = tmp_path / "phase4_module_linkage_report.json"
            self._write_matrix(matrix_path)
            self._write_checklist(
                checklist_path,
                adp_statuses=["PARTIAL", "TO_AUDIT"],
                copilot_statuses=["PARTIAL", "PARTIAL"],
            )
            self._write_reference_map(reference_map_path)

            proc = run_script(
                PROTOTYPE_DIR / "phase4_module_linkage_check_stub.py",
                "--matrix",
                str(matrix_path),
                "--checklist",
                str(checklist_path),
                "--reference-map",
                str(reference_map_path),
                "--module",
                "adp",
                "--module",
                "copilot",
                "--out",
                str(out_path),
            )
            self.assertIn("[ok] module=adp matrix_status=PHASE4_IN_PROGRESS ready_row_count=1", proc.stdout)
            self.assertIn("[ok] module=copilot matrix_status=PHASE4_IN_PROGRESS ready_row_count=2", proc.stdout)
            payload = read_json_file(self, file_path=out_path)
            self.assertEqual(payload.get("phase4_module_linkage_report_schema_version"), "phase4_module_linkage_report_v0")
            modules = payload.get("modules", [])
            self.assertEqual(len(modules), 2)
            adp = modules[0]
            self.assertEqual(adp.get("module"), "adp")
            self.assertEqual(
                adp.get("reference_repositories"),
                ["autowarefoundation/autoware", "carla-simulator/carla"],
            )
            self.assertEqual(adp.get("reference_priority"), "P1")
            self.assertEqual(adp.get("reference_repository_count"), 2)
            self.assertEqual(adp.get("reference_pattern_to_extract"), "pattern")
            self.assertEqual(adp.get("reference_local_first_target"), "target")

    def test_rejects_module_missing_in_reference_map(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            matrix_path = tmp_path / "STACK_MODULE_PARITY_MATRIX.md"
