class Phase4ReferencePatternScanStubTests(unittest.TestCase):
    def _write_reference_map(
        self,
        path: Path,
        *,
        hil_sim_pattern: str = "ROS2 interface contracts, simulation bridge flow, test harness launch patterns",
        adp_pattern: str = "unified workflow surface (scenario->execution->analysis), use-case traceability structure",
        copilot_pattern: str = "prompt-driven safety guardrails, replay/query assist loop patterns",
    ) -> None:
        path.write_text(
            "\n".join(
                [
                    "# Phase-4 External Reference Map",
                    "",
                    "| Phase-4 Module | Priority | Primary References | Pattern to Extract | Local First Target |",
                    "|---|---|---|---|---|",
                    f"| `hil_sim` | P0 | `autowarefoundation/autoware`, `tier4/AWSIM` | {hil_sim_pattern} | target_hil |",
                    f"| `adp` | P1 | `autowarefoundation/autoware`, `carla-simulator/carla` | {adp_pattern} | target_adp |",
                    f"| `copilot` | P1 | `commaai/openpilot`, `carla-simulator/carla` | {copilot_pattern} | target_copilot |",
                    "",
                ]
            ),
            encoding="utf-8",
        )

    def _write_reference_index(
        self,
        path: Path,
        *,
        include_openpilot: bool = True,
        autoware_patterns: list[str] | None = None,
        awsim_patterns: list[str] | None = None,
        carla_patterns: list[str] | None = None,
        openpilot_patterns: list[str] | None = None,
    ) -> None:
        autoware_observed_patterns = (
            list(autoware_patterns)
            if autoware_patterns is not None
            else [
                "ROS2 interface contracts",
                "test harness launch patterns",
                "unified workflow surface scenario execution analysis",
                "use-case traceability structure",
            ]
        )
        awsim_observed_patterns = (
            list(awsim_patterns) if awsim_patterns is not None else ["simulation bridge flow", "ROS2 interface contracts"]
        )
        carla_observed_patterns = (
            list(carla_patterns)
            if carla_patterns is not None
            else [
                "unified workflow surface scenario execution analysis",
                "replay query assist loop patterns",
                "use-case traceability structure",
            ]
        )
        openpilot_observed_patterns = (
            list(openpilot_patterns)
            if openpilot_patterns is not None
            else [
                "prompt-driven safety guardrails",
                "replay query assist loop patterns",
            ]
        )
        repositories: list[dict[str, object]] = [
            {
                "repository": "autowarefoundation/autoware",
                "observed_patterns": autoware_observed_patterns,
            },
            {
                "repository": "tier4/AWSIM",
                "observed_patterns": awsim_observed_patterns,
            },
            {
                "repository": "carla-simulator/carla",
                "observed_patterns": carla_observed_patterns,
            },
        ]
        if include_openpilot:
            repositories.append(
                {
                    "repository": "commaai/openpilot",
                    "observed_patterns": openpilot_observed_patterns,
                }
            )
        path.write_text(
            json.dumps(
                {
                    "phase4_reference_index_schema_version": "phase4_reference_index_v0",
                    "generated_at": "2026-01-01T00:00:00+00:00",
                    "repositories": repositories,
                },
                ensure_ascii=True,
                indent=2,
            )
            + "\n",
            encoding="utf-8",
        )

    def test_validates_reference_pattern_scan_coverage(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            reference_map_path = tmp_path / "PHASE4_EXTERNAL_REFERENCE_MAP.md"
            reference_index_path = tmp_path / "phase4_reference_index.json"
            out_path = tmp_path / "phase4_reference_pattern_scan_report.json"
            self._write_reference_map(reference_map_path)
            self._write_reference_index(reference_index_path)

            proc = run_script(
                PROTOTYPE_DIR / "phase4_reference_pattern_scan_stub.py",
                "--reference-map",
                str(reference_map_path),
                "--reference-index",
                str(reference_index_path),
                "--module",
                "hil_sim",
                "--module",
                "adp",
                "--module",
                "copilot",
                "--out",
                str(out_path),
            )
            self.assertIn("[ok] module=hil_sim matched=3/3 coverage=1.000", proc.stdout)
            self.assertIn("[ok] module=adp matched=2/2 coverage=1.000", proc.stdout)
            self.assertIn("[ok] module=copilot matched=2/2 coverage=1.000", proc.stdout)
            payload = read_json_file(self, file_path=out_path)
            self.assertEqual(
                payload.get("phase4_reference_pattern_scan_report_schema_version"),
                "phase4_reference_pattern_scan_report_v0",
            )
            self.assertEqual(payload.get("reference_index_schema_version"), "phase4_reference_index_v0")
            self.assertEqual(int(payload.get("module_count", 0)), 3)
            self.assertEqual(int(payload.get("total_expected_pattern_count", 0)), 7)
            self.assertEqual(int(payload.get("total_matched_pattern_count", 0)), 7)
            self.assertAlmostEqual(float(payload.get("total_coverage_ratio", 0.0)), 1.0)
            modules = payload.get("modules", [])
            self.assertEqual([item.get("module") for item in modules], ["hil_sim", "adp", "copilot"])

