class DatasetManifestTests(unittest.TestCase):
    def test_builds_dataset_manifest_from_summaries(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            run_root = tmp_path / "runs"
            release_root = tmp_path / "reports"
            run_summary = run_root / "run_001" / "summary.json"
            release_summary = release_root / "REL_001.summary.json"
            run_summary.parent.mkdir(parents=True, exist_ok=True)
            release_summary.parent.mkdir(parents=True, exist_ok=True)
            run_summary.write_text(
                json.dumps(
                    {
                        "run_id": "run_001",
                        "sds_version": "sds_v1",
                        "map_id": "map_demo_v0",
                        "status": "success",
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            release_summary.write_text(
                json.dumps(
                    {
                        "release_id": "REL_001",
                        "sds_version": "sds_v1",
                        "final_result": "PASS",
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            out_path = tmp_path / "dataset_manifest.json"
            proc = run_script(
                PROTOTYPE_DIR / "../../P_Data-Lake-and-Explorer/prototype/build_dataset_manifest.py",
                "--summary-root",
                str(run_root),
                "--release-summary-root",
                str(release_root),
                "--dataset-id",
                "dataset_demo_001",
                "--out",
                str(out_path),
            )
            self.assertIn("[ok] run_summary_count=1", proc.stdout)
            self.assertIn("[ok] release_summary_count=1", proc.stdout)
            payload = read_json_file(self, file_path=out_path)
            self.assertEqual(payload.get("dataset_manifest_schema_version"), "dataset_manifest_v0")
            self.assertEqual(payload.get("dataset_id"), "dataset_demo_001")
            self.assertEqual(payload.get("run_summary_count"), 1)
            self.assertEqual(payload.get("release_summary_count"), 1)
            self.assertEqual(payload.get("sds_versions"), ["sds_v1"])
            self.assertEqual(payload.get("run_ids"), ["run_001"])
            self.assertEqual(payload.get("release_ids"), ["REL_001"])

