class RunCiMatrixPipelineTests(unittest.TestCase):
    def test_dry_run_executes_selected_profile_and_writes_summary(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            profiles_path = tmp_path / "profiles.json"
            profiles_path.write_text(
                json.dumps(
                    {
                        "profiles": [
                            {
                                "profile_id": "alpha",
                                "default_batch_spec": "a.json",
                                "default_sds_versions": "sds_a",
                            },
                            {
                                "profile_id": "beta",
                                "default_batch_spec": "b.json",
                                "default_sds_versions": "sds_b",
                            },
                        ]
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            fake_runner = tmp_path / "fake_run_ci_pipeline.py"
            fake_runner.write_text(
                "import sys\n"
                "args = sys.argv[1:]\n"
                "def get(flag):\n"
                "    idx = args.index(flag)\n"
                "    return args[idx + 1]\n"
                "profile_id = get('--profile-id')\n"
                "release_id = get('--release-id')\n"
                "print(f'[ok] fake profile_id={profile_id} release_id={release_id}')\n"
                "sys.exit(0)\n",
                encoding="utf-8",
            )

            summary_out = tmp_path / "matrix_summary.json"
            proc = run_script(
                PROTOTYPE_DIR / "run_ci_matrix_pipeline.py",
                "--profiles-file",
                str(profiles_path),
                "--profile-loader",
                str(PROTOTYPE_DIR / "load_ci_matrix.py"),
                "--pipeline-runner",
                str(fake_runner),
                "--release-prefix",
                "REL_MATRIX_TEST_001",
                "--profile-ids-csv",
                "beta",
                "--summary-out",
                str(summary_out),
                "--dry-run",
            )

            self.assertIn("[ok] matrix_profile=beta release_id=REL_MATRIX_TEST_001_beta", proc.stdout)
            self.assertNotIn("matrix_profile=alpha", proc.stdout)
            self.assertNotIn('"include"', proc.stdout)
            self.assertTrue(summary_out.exists())
            summary_payload = read_json_file(self, file_path=summary_out)
            self.assertEqual(summary_payload.get("profile_count"), 1)
            self.assertEqual(summary_payload.get("failure_count"), 0)
            results = summary_payload.get("results", [])
            self.assertEqual(len(results), 1)
            self.assertEqual(results[0].get("profile_id"), "beta")
            self.assertEqual(results[0].get("release_id"), "REL_MATRIX_TEST_001_beta")
            self.assertEqual(results[0].get("status"), "ok")

