    def test_runtime_artifact_assertion_fails_without_ci_manifest_output(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            profiles_path = tmp_path / "profiles.json"
            profiles_path.write_text(
                json.dumps(
                    {
                        "profiles": [
                            {
                                "profile_id": "runtime",
                                "default_batch_spec": "runtime_batch.json",
                                "default_sds_versions": "sds_runtime",
                            }
                        ]
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            fake_runner = tmp_path / "fake_run_ci_pipeline.py"
            fake_runner.write_text(
                "import sys\n"
                "args = sys.argv[1:]\n"
                "def get(flag):\n"
                "    idx = args.index(flag)\n"
                "    return args[idx + 1]\n"
                "profile_id = get('--profile-id')\n"
                "release_id = get('--release-id')\n"
                "print(f'[ok] fake profile_id={profile_id} release_id={release_id}')\n"
                "sys.exit(0)\n",
                encoding="utf-8",
            )

            summary_out = tmp_path / "matrix_summary.json"
            proc = run_script(
                PROTOTYPE_DIR / "run_ci_matrix_pipeline.py",
                "--profiles-file",
                str(profiles_path),
                "--profile-loader",
                str(PROTOTYPE_DIR / "load_ci_matrix.py"),
                "--pipeline-runner",
                str(fake_runner),
                "--release-prefix",
                "REL_MATRIX_RUNTIME_ASSERT_002",
                "--sim-runtime",
                "carla",
                "--sim-runtime-assert-artifacts-input",
                "true",
                "--summary-out",
                str(summary_out),
                expected_rc=1,
            )

            self.assertIn("[error] run_ci_matrix_pipeline.py:", proc.stderr)
            self.assertIn(
                "runtime artifact assertion failed for profile runtime: missing [ok] ci_manifest_path output from run_ci_pipeline.py",
                proc.stderr,
            )
            summary_payload = read_json_file(self, file_path=summary_out)
            self.assertEqual(summary_payload.get("profile_count"), 1)
            self.assertEqual(summary_payload.get("failure_count"), 1)
            result = summary_payload.get("results", [{}])[0]
            self.assertEqual(result.get("status"), "failed")
            self.assertEqual(int(result.get("returncode", -1)), 2)

