class UpdateStackProgressLogTests(unittest.TestCase):
    def test_updates_existing_date_section_with_new_entry_on_top(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            log_path = tmp_path / "STACK_PROGRESS_LOG.md"
            log_path.write_text(
                "\n".join(
                    [
                        "# E2E Stack Progress Log",
                        "",
                        "## 2026-02-28",
                        "",
                        "- `old1234` existing entry",
                        "",
                        "## 2026-02-27",
                        "",
                        "- `older111` previous day",
                    ]
                )
                + "\n",
                encoding="utf-8",
            )

            run_script(
                PROTOTYPE_DIR / "update_stack_progress_log.py",
                "--log-file",
                str(log_path),
                "--date",
                "2026-02-28",
                "--entry",
                "`new5678` new entry",
            )

            log_text = log_path.read_text(encoding="utf-8")
            self.assertIn("## 2026-02-28", log_text)
            self.assertIn("- `new5678` new entry", log_text)
            self.assertIn("- `old1234` existing entry", log_text)
            self.assertLess(log_text.index("- `new5678` new entry"), log_text.index("- `old1234` existing entry"))

    def test_creates_missing_date_section_before_existing_sections(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            log_path = tmp_path / "STACK_PROGRESS_LOG.md"
            log_path.write_text(
                "\n".join(
                    [
                        "# E2E Stack Progress Log",
                        "",
                        "## 2026-02-27",
                        "",
                        "- `older111` previous day",
                    ]
                )
                + "\n",
                encoding="utf-8",
            )

            run_script(
                PROTOTYPE_DIR / "update_stack_progress_log.py",
                "--log-file",
                str(log_path),
                "--date",
                "2026-02-28",
                "--entry",
                "`new5678` new entry",
            )

            log_text = log_path.read_text(encoding="utf-8")
            self.assertIn("## 2026-02-28", log_text)
            self.assertIn("## 2026-02-27", log_text)
            self.assertLess(log_text.index("## 2026-02-28"), log_text.index("## 2026-02-27"))

    def test_skips_when_entry_already_exists(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            log_path = tmp_path / "STACK_PROGRESS_LOG.md"
            baseline = (
                "\n".join(
                    [
                        "# E2E Stack Progress Log",
                        "",
                        "## 2026-02-28",
                        "",
                        "- `new5678` new entry",
                        "- `old1234` existing entry",
                    ]
                )
                + "\n"
            )
            log_path.write_text(baseline, encoding="utf-8")

            proc = run_script(
                PROTOTYPE_DIR / "update_stack_progress_log.py",
                "--log-file",
                str(log_path),
                "--date",
                "2026-02-28",
                "--entry",
                "`new5678` new entry",
            )
            self.assertIn("[skip] entry already exists", proc.stdout)
            self.assertEqual(log_path.read_text(encoding="utf-8"), baseline)

    def test_invalid_date_writes_ci_error_summary(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            log_path = tmp_path / "STACK_PROGRESS_LOG.md"
            step_summary = tmp_path / "step_summary.md"
            log_path.write_text("# E2E Stack Progress Log\n", encoding="utf-8")

            proc = run_text_process(
                [
                    PYTHON,
                    str(PROTOTYPE_DIR / "update_stack_progress_log.py"),
                    "--log-file",
                    str(log_path),
                    "--date",
                    "2026/02/28",
                    "--entry",
                    "x",
                ],
                capture_output=True,
                env=step_summary_env(step_summary),
            )
            self.assertEqual(proc.returncode, 1)
            self.assertIn("[error] update_stack_progress_log.py:", proc.stderr)
            self.assertIn("date must be YYYY-MM-DD", proc.stderr)
            assert_step_summary_ci_error(
                self,
                step_summary_path=step_summary,
                source="update_stack_progress_log.py",
                phase=PHASE_RESOLVE_INPUTS,
                message_substring="date must be YYYY-MM-DD",
            )


class SyncUtilsTests(unittest.TestCase):
    def test_replace_marker_block_updates_contents(self) -> None:
        source = "\n".join(
            [
                "a",
                "# BEGIN AUTO",
                "stale",
                "# END AUTO",
                "z",
            ]
        )
        rendered = replace_marker_block(
            source,
            begin_marker="# BEGIN AUTO",
            end_marker="# END AUTO",
            generated_lines=["x", "y"],
            subject="test",
        )
        self.assertEqual(rendered, "a\n# BEGIN AUTO\nx\ny\n# END AUTO\nz\n")

