    def test_phase4_linkage_contract_normalizer_calls_str_once_per_value(self) -> None:
        class CountingValue:
            def __init__(self, text: str) -> None:
                self.text = text
                self.calls = 0

            def __str__(self) -> str:
                self.calls += 1
                return self.text

        value = CountingValue(" ADP ")
        self.assertEqual(
            normalize_phase4_linkage_modules([value], default_to_allowed_when_empty=False),
            ["adp"],
        )
        self.assertEqual(value.calls, 1)

    def test_phase4_reference_pattern_contract_normalizer_calls_str_once_per_value(self) -> None:
        class CountingValue:
            def __init__(self, text: str) -> None:
                self.text = text
                self.calls = 0

            def __str__(self) -> str:
                self.calls += 1
                return self.text

        value = CountingValue(" HiL_Sim ")
        self.assertEqual(
            normalize_phase4_reference_pattern_modules([value], default_to_allowed_when_empty=False),
            ["hil_sim"],
        )
        self.assertEqual(value.calls, 1)

    def test_phase4_contract_normalizers_use_shared_normalize_helper(self) -> None:
        contract_text = (PROTOTYPE_DIR / "phase4_linkage_contract.py").read_text(encoding="utf-8")
        self.assertIn("def _normalize_modules(", contract_text)
        for function_name in ("normalize_phase4_linkage_modules", "normalize_phase4_reference_pattern_modules"):
            function_start = contract_text.find(f"def {function_name}(")
            self.assertNotEqual(function_start, -1)
            function_text = contract_text[function_start:]
            next_function_start = function_text.find("\ndef ", 1)
            if next_function_start >= 0:
                function_text = function_text[:next_function_start]
            body = function_text
            self.assertIn("_normalize_modules(", body)
            self.assertNotIn("for value in values", body)

