class SubprocessHelpersTests(unittest.TestCase):
    def test_run_command_replaces_non_utf8_bytes_when_capturing_output(self) -> None:
        proc = run_command(
            [
                PYTHON,
                "-c",
                "import sys; sys.stdout.buffer.write(b'\\xff\\n'); sys.stderr.buffer.write(b'\\xfe\\n')",
            ],
            capture_output=True,
        )
        self.assertEqual(proc.returncode, 0)
        self.assertIsNotNone(proc.stdout)
        self.assertIsNotNone(proc.stderr)
        self.assertIn("\ufffd", str(proc.stdout))
        self.assertIn("\ufffd", str(proc.stderr))

    def test_run_capture_stdout_or_raise_returns_stdout_and_emits_streams(self) -> None:
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
            captured = run_capture_stdout_or_raise(
                [
                    PYTHON,
                    "-c",
                    "import sys; print('alpha'); print('beta', file=sys.stderr)",
                ]
            )
        self.assertEqual(captured.strip(), "alpha")
        self.assertIn("alpha", stdout_buffer.getvalue())
        self.assertIn("beta", stderr_buffer.getvalue())

    def test_run_capture_stdout_or_raise_raises_with_compact_failure(self) -> None:
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with self.assertRaises(RuntimeError) as cm:
            with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
                run_capture_stdout_or_raise(
                    [
                        PYTHON,
                        "-c",
                        "import sys; print('[error] boom', file=sys.stderr); sys.exit(2)",
                    ]
                )
        self.assertIn("failed with exit code 2", str(cm.exception))
        self.assertIn("[error] boom", str(cm.exception))
        self.assertIn("[error] boom", stderr_buffer.getvalue())

    def test_run_capture_stdout_or_raise_can_skip_success_output(self) -> None:
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
            captured = run_capture_stdout_or_raise(
                [
                    PYTHON,
                    "-c",
                    "print('alpha')",
                ],
                emit_output_on_success=False,
            )
        self.assertEqual(captured.strip(), "alpha")
        self.assertNotIn("alpha", stdout_buffer.getvalue())
        self.assertEqual("", stderr_buffer.getvalue())

    def test_run_capture_stdout_or_raise_can_skip_failure_output(self) -> None:
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with self.assertRaises(RuntimeError) as cm:
            with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
                run_capture_stdout_or_raise(
                    [
                        PYTHON,
                        "-c",
                        "import sys; print('[error] hidden', file=sys.stderr); sys.exit(4)",
                    ],
                    emit_output_on_failure=False,
                )
        self.assertIn("failed with exit code 4", str(cm.exception))
        self.assertIn("[error] hidden", str(cm.exception))
        self.assertEqual("", stdout_buffer.getvalue())
        self.assertEqual("", stderr_buffer.getvalue())

    def test_run_logged_capture_stdout_or_raise_logs_command(self) -> None:
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
            captured = run_logged_capture_stdout_or_raise(
                [
                    PYTHON,
                    "-c",
                    "print('alpha')",
                ],
                emit_output_on_success=False,
            )
        self.assertEqual(captured.strip(), "alpha")
        self.assertIn("[cmd]", stdout_buffer.getvalue())
        self.assertIn("-c", stdout_buffer.getvalue())
        self.assertEqual("", stderr_buffer.getvalue())

    def test_run_logged_capture_stdout_or_raise_uses_failure_context(self) -> None:
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with self.assertRaises(RuntimeError) as cm:
            with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
                run_logged_capture_stdout_or_raise(
                    [
                        PYTHON,
                        "-c",
                        "import sys; sys.exit(6)",
                    ],
                    context="demo",
                )
        self.assertIn("demo failed with exit code 6", str(cm.exception))
        self.assertIn("[cmd]", stdout_buffer.getvalue())
        self.assertEqual("", stderr_buffer.getvalue())

    def test_run_command_or_raise_uses_display_cmd_and_can_suppress_failure_output(self) -> None:
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with self.assertRaises(RuntimeError) as cm:
            with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
                run_command_or_raise(
                    [PYTHON, "-c", "import sys; print('[error] hidden', file=sys.stderr); sys.exit(4)"],
                    capture_output=True,
                    context="demo",
                    display_cmd="python3 tool.py --webhook-url ***",
                    emit_output_on_failure=False,
                )
        self.assertIn("demo failed with exit code 4: python3 tool.py --webhook-url ***", str(cm.exception))
        self.assertIn("[error] hidden", str(cm.exception))
        self.assertEqual("", stdout_buffer.getvalue())
        self.assertEqual("", stderr_buffer.getvalue())

    def test_run_logged_command_or_raise_uses_display_cmd_for_logging(self) -> None:
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
            proc = run_logged_command_or_raise(
                [PYTHON, "-c", "print('alpha')"],
                capture_output=True,
                display_cmd="python3 tool.py --webhook-url ***",
                emit_output_on_success=False,
            )
        self.assertEqual(proc.returncode, 0)
        self.assertIn("[cmd] python3 tool.py --webhook-url ***", stdout_buffer.getvalue())
        self.assertNotIn("alpha", stdout_buffer.getvalue())
        self.assertEqual("", stderr_buffer.getvalue())

    def test_run_logged_command_or_raise_preserves_failure_detail(self) -> None:
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with self.assertRaises(RuntimeError) as cm:
            with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
                run_logged_command_or_raise(
                    [PYTHON, "-c", "import sys; print('[error] boom', file=sys.stderr); sys.exit(5)"],
                    capture_output=True,
                    context="demo",
                    display_cmd="python3 tool.py --webhook-url ***",
                    emit_output_on_failure=False,
                )
        self.assertIn("demo failed with exit code 5: python3 tool.py --webhook-url ***", str(cm.exception))
        self.assertIn("[error] boom", str(cm.exception))
        self.assertIn("[cmd] python3 tool.py --webhook-url ***", stdout_buffer.getvalue())
        self.assertEqual("", stderr_buffer.getvalue())

    def test_emit_captured_output_preserves_stderr_stream(self) -> None:
        proc = subprocess.CompletedProcess(
            args=["python3", "-c", "pass"],
            returncode=0,
            stdout="alpha\n",
            stderr="beta\n",
        )
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
            emit_captured_output(proc)

        stdout_lines = [line.strip() for line in stdout_buffer.getvalue().splitlines() if line.strip()]
        stderr_lines = [line.strip() for line in stderr_buffer.getvalue().splitlines() if line.strip()]
        self.assertIn("alpha", stdout_lines)
        self.assertNotIn("beta", stdout_lines)
        self.assertIn("beta", stderr_lines)

    def test_emit_captured_output_can_skip_stdout(self) -> None:
        proc = subprocess.CompletedProcess(
            args=["python3", "-c", "pass"],
            returncode=0,
            stdout="alpha\n",
            stderr="beta\n",
        )
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
            emit_captured_output(proc, print_stdout=False)

        self.assertNotIn("alpha", stdout_buffer.getvalue())
        self.assertIn("beta", stderr_buffer.getvalue())

    def test_emit_captured_output_can_skip_stderr(self) -> None:
        proc = subprocess.CompletedProcess(
            args=["python3", "-c", "pass"],
            returncode=0,
            stdout="alpha\n",
            stderr="beta\n",
        )
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
            emit_captured_output(proc, print_stderr=False)

        self.assertIn("alpha", stdout_buffer.getvalue())
        self.assertNotIn("beta", stderr_buffer.getvalue())

    def test_format_subprocess_failure_prefers_stderr_detail(self) -> None:
        message = format_subprocess_failure(
            ["python3", "tool.py", "--flag"],
            returncode=2,
            stdout="stdout detail",
            stderr="stderr detail",
            context="profile resolution",
        )
        self.assertIn("profile resolution failed with exit code 2", message)
        self.assertIn("python3 tool.py --flag", message)
        self.assertIn("stderr detail", message)
        self.assertNotIn("stdout detail", message)

    def test_format_subprocess_failure_uses_stdout_when_stderr_empty(self) -> None:
        message = format_subprocess_failure(
            ["python3", "tool.py"],
            returncode=1,
            stdout="stdout detail",
            stderr="",
            context="command",
        )
        self.assertIn("command failed with exit code 1", message)
        self.assertIn("stdout detail", message)

    def test_format_subprocess_failure_uses_display_cmd_override(self) -> None:
        message = format_subprocess_failure(
            ["python3", "tool.py", "--secret", "value"],
            returncode=3,
            stdout="",
            stderr="boom",
            context="command",
            display_cmd="python3 tool.py --secret ***",
        )
        self.assertIn("python3 tool.py --secret ***", message)
        self.assertNotIn("--secret value", message)

    def test_format_subprocess_failure_prefers_error_line_from_stdout(self) -> None:
        message = format_subprocess_failure(
            ["python3", "tool.py"],
            returncode=5,
            stdout="progress\n[error] stdout failed detail",
            stderr="non-fatal warning",
            context="command",
        )
        self.assertIn("[error] stdout failed detail", message)
        self.assertNotIn("non-fatal warning", message)

    def test_format_subprocess_failure_prefers_error_line_from_stderr_first(self) -> None:
        message = format_subprocess_failure(
            ["python3", "tool.py"],
            returncode=5,
            stdout="[error] stdout failed detail",
            stderr="[error] stderr failed detail",
            context="command",
        )
        self.assertIn("[error] stderr failed detail", message)
        self.assertNotIn("[error] stdout failed detail", message)

    def test_format_subprocess_failure_uses_last_stderr_line_when_no_error_marker(self) -> None:
        message = format_subprocess_failure(
            ["python3", "tool.py"],
            returncode=5,
            stdout="stdout first\nstdout last",
            stderr="stderr first\nstderr last",
            context="command",
        )
        self.assertIn("stderr last", message)
        self.assertNotIn("stderr first", message)
        self.assertNotIn("stdout last", message)

    def test_format_subprocess_failure_uses_last_stdout_line_when_stderr_empty(self) -> None:
        message = format_subprocess_failure(
            ["python3", "tool.py"],
            returncode=5,
            stdout="stdout first\nstdout last",
            stderr="",
            context="command",
        )
        self.assertIn("stdout last", message)
        self.assertNotIn("stdout first", message)

    def test_format_subprocess_failure_compacts_multiline_detail(self) -> None:
        message = format_subprocess_failure(
            ["python3", "tool.py"],
            returncode=1,
            stdout="",
            stderr="line1\nline2\tline3",
            context="command",
        )
        self.assertIn("line2 line3", message)
        self.assertNotIn("\nline2", message)

    def test_compact_failure_detail_truncates_long_text(self) -> None:
        detail = compact_failure_detail("x" * 500, max_chars=100)
        self.assertTrue(detail.startswith("x" * 100))
        self.assertIn("... (+400 chars)", detail)


class SyncNightlyMatrixScopeTests(unittest.TestCase):
    def test_scope_sync_check_passes_for_repo_files(self) -> None:
        run_script(PROTOTYPE_DIR / "sync_nightly_matrix_scope.py", "--check")

    def test_scope_sync_generates_profiles_and_readme(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            scope_path = tmp_path / "scope.json"
            profiles_path = tmp_path / "profiles.json"
            readme_path = tmp_path / "README.md"
            workflow_path = tmp_path / "e2e-nightly.yml"
            scope_path.write_text(
                json.dumps(
                    {
                        "profiles": [
                            {
                                "profile_id": "alpha",
                                "default_batch_spec": "30_Projects/P_Cloud-Engine/prototype/examples/batch_a.json",
                                "default_sds_versions": "sds_a",
                            },
                            {
                                "profile_id": "beta",
                                "default_batch_spec": "30_Projects/P_Cloud-Engine/prototype/examples/batch_b.json",
                                "default_sds_versions": "sds_b",
                            },
                        ]
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            profiles_path.write_text('{"profiles":[]}\n', encoding="utf-8")
            readme_path.write_text(
                "\n".join(
                    [
                        "Nightly 기본 매트릭스 프로필:",
                        "",
                        "<!-- BEGIN AUTO-GENERATED NIGHTLY MATRIX PROFILES -->",
                        "- stale",
                        "<!-- END AUTO-GENERATED NIGHTLY MATRIX PROFILES -->",
                        "- profiles file: `x`",
                    ]
                )
                + "\n",
                encoding="utf-8",
            )
            workflow_path.write_text(
                "\n".join(
                    [
                        "name: Nightly",
                        "on:",
                        "  workflow_dispatch:",
                        "    inputs:",
                        "      matrix_profile_file:",
                        "        # BEGIN AUTO-GENERATED NIGHTLY MATRIX PROFILE FILE",
                        "        default: \"stale.json\"",
                        "        # END AUTO-GENERATED NIGHTLY MATRIX PROFILE FILE",
                    ]
                )
                + "\n",
                encoding="utf-8",
            )

            run_script(
                PROTOTYPE_DIR / "sync_nightly_matrix_scope.py",
                "--scope-file",
                str(scope_path),
                "--profiles-file",
                str(profiles_path),
                "--readme-file",
                str(readme_path),
                "--workflow-file",
                str(workflow_path),
                "--workflow-profile-file-default",
                "custom/nightly_profiles.json",
            )

            generated_profiles = read_json_file(self, file_path=profiles_path)
            self.assertEqual(len(generated_profiles["profiles"]), 2)
            self.assertEqual(generated_profiles["profiles"][0]["profile_id"], "alpha")
            self.assertEqual(generated_profiles["profiles"][1]["profile_id"], "beta")
            readme_text = readme_path.read_text(encoding="utf-8")
            self.assertIn(
                "- `alpha` -> `30_Projects/P_Cloud-Engine/prototype/examples/batch_a.json`",
                readme_text,
            )
            self.assertIn(
                "- `beta` -> `30_Projects/P_Cloud-Engine/prototype/examples/batch_b.json`",
                readme_text,
            )
            workflow_text = workflow_path.read_text(encoding="utf-8")
            self.assertIn('default: "custom/nightly_profiles.json"', workflow_text)

