    def test_phase4_allowed_modules_case_branches_match_python_contract(self) -> None:
        helper_text = (PROTOTYPE_DIR / "ci_phases_shell.sh").read_text(encoding="utf-8")

        for function_name, expected_modules in (
            ("ci_phase4_linkage_is_allowed_module", PHASE4_LINKAGE_ALLOWED_MODULES),
            ("ci_phase4_reference_pattern_is_allowed_module", PHASE4_REFERENCE_PATTERN_ALLOWED_MODULES),
        ):
            function_match = re.search(rf"{function_name}\(\) \{{\n(?P<body>.*?)\n\}}", helper_text, re.DOTALL)
            self.assertIsNotNone(function_match)
            body = function_match.group("body")
            case_match = re.search(
                r'case "\$\{module\}" in\n(?P<arms>.*?)\n    \*\)',
                body,
                re.DOTALL,
            )
            self.assertIsNotNone(case_match)
            arms = case_match.group("arms")
            shell_modules: list[str] = []
            for raw_line in arms.splitlines():
                stripped = raw_line.strip()
                if not stripped or stripped.startswith("return") or stripped == ";;":
                    continue
                if not stripped.endswith(")") or stripped.startswith("*"):
                    continue
                shell_modules.extend(item.strip() for item in stripped[:-1].split("|") if item.strip())

            self.assertEqual(shell_modules, list(expected_modules))

