    def test_python_entry_scripts_with_wrapper_enable_summary_env_fallback(self) -> None:
        skipped = {"ci_script_entry.py"}
        for script_path in sorted(PROTOTYPE_DIR.glob("*.py")):
            if script_path.name in skipped:
                continue
            text = script_path.read_text(encoding="utf-8")
            if "run_with_error_handling(" not in text:
                continue
            call_expr = extract_first_call_expression(text, "run_with_error_handling")
            self.assertNotEqual(
                call_expr,
                "",
                msg=f"{script_path.name} must include a parseable run_with_error_handling(...) call",
            )
            self.assertIn(
                "step_summary_file=resolve_step_summary_file_from_env()",
                call_expr,
                msg=f"{script_path.name} must pass shared step-summary env resolver to run_with_error_handling",
            )
            self.assertIn(
                "phase=",
                call_expr,
                msg=f"{script_path.name} must pass phase detail to run_with_error_handling",
            )

    def test_validate_python_entry_scripts_have_step_summary_fallback_contract(self) -> None:
        makefile_path = PROTOTYPE_DIR / "Makefile"
        entries = parse_validate_py_compile_entries(makefile_path)
        for entry in entries:
            script_path = (PROTOTYPE_DIR / entry).resolve()
            if not script_path.exists():
                continue
            text = script_path.read_text(encoding="utf-8")
            if 'if __name__ == "__main__":' not in text:
                continue

            if "run_with_error_handling(" in text:
                call_expr = extract_first_call_expression(text, "run_with_error_handling")
                self.assertNotEqual(
                    call_expr,
                    "",
                    msg=f"{script_path.name} must include a parseable run_with_error_handling(...) call",
                )
                self.assertIn(
                    "step_summary_file=resolve_step_summary_file_from_env()",
                    call_expr,
                    msg=(
                        f"{script_path.name} must pass shared step-summary env resolver "
                        "to run_with_error_handling"
                    ),
                )
                self.assertIn(
                    "phase=",
                    call_expr,
                    msg=f"{script_path.name} must pass phase detail to run_with_error_handling",
                )
                continue

            if "emit_ci_error(" in text:
                self.assertIn(
                    "resolve_step_summary_file_from_env()",
                    text,
                    msg=f"{script_path.name} must resolve step summary path from env fallback",
                )
                continue

            if "from ci_error_summary import write_ci_error_summary" in text:
                self.assertIn(
                    "write_ci_error_summary(",
                    text,
                    msg=f"{script_path.name} must emit CI error summary through shared helper",
                )
                continue

            self.assertIn(
                "def _resolve_step_summary_file_from_env()",
                text,
                msg=f"{script_path.name} must define local step-summary env resolver",
            )
            self.assertIn(
                'os.environ.get("STEP_SUMMARY_FILE", "").strip()',
                text,
                msg=f"{script_path.name} must read STEP_SUMMARY_FILE",
            )
            self.assertIn(
                'os.environ.get("GITHUB_STEP_SUMMARY", "").strip()',
                text,
                msg=f"{script_path.name} must fallback to GITHUB_STEP_SUMMARY",
            )
            self.assertIn(
                'CI_ERROR_TITLE = "E2E CI Error"',
                text,
                msg=f"{script_path.name} must use E2E CI Error summary contract",
            )
            self.assertIn(
                "_write_ci_error_summary(",
                text,
                msg=f"{script_path.name} must wire CI error summary emission",
            )

    def test_module_ci_error_summary_helpers_have_shared_contract(self) -> None:
        repo_root = PROTOTYPE_DIR.parents[2]
        makefile_entries = parse_validate_py_compile_entries(PROTOTYPE_DIR / "Makefile")
        helper_entries = sorted(
            entry
            for entry in makefile_entries
            if entry.endswith("/prototype/ci_error_summary.py")
        )
        self.assertEqual(
            len(helper_entries),
            len(set(helper_entries)),
            msg="Makefile validate py_compile entries must not duplicate module ci_error_summary.py paths",
        )

        helper_paths_from_makefile = sorted((PROTOTYPE_DIR / entry).resolve() for entry in helper_entries)
        helper_paths_from_glob = sorted(repo_root.glob("30_Projects/*/prototype/ci_error_summary.py"))
        self.assertEqual(
            helper_paths_from_makefile,
            helper_paths_from_glob,
            msg=(
                "Makefile validate py_compile helper inventory must match repository module "
                "ci_error_summary.py files"
            ),
        )

        helper_path_set = set(helper_paths_from_makefile)
        for entry in makefile_entries:
            script_path = (PROTOTYPE_DIR / entry).resolve()
            if not script_path.exists() or script_path.name == "ci_error_summary.py":
                continue
            text = script_path.read_text(encoding="utf-8")
            if "from ci_error_summary import " not in text:
                continue
            helper_path = script_path.with_name("ci_error_summary.py")
            self.assertTrue(
                helper_path.exists(),
                msg=f"{script_path.name} imports ci_error_summary but sibling helper file is missing",
            )
            self.assertIn(
                helper_path,
                helper_path_set,
                msg=(
                    f"{script_path.name} imports ci_error_summary but {helper_path.name} "
                    "is not included in Makefile validate py_compile entries"
                ),
            )

        for helper_path in helper_paths_from_makefile:
            text = helper_path.read_text(encoding="utf-8")
            self.assertIn(
                'CI_ERROR_TITLE = "E2E CI Error"',
                text,
                msg=f"{helper_path.name} must define E2E CI Error title contract",
            )
            self.assertIn(
                "def resolve_step_summary_file_from_env() -> str:",
                text,
                msg=f"{helper_path.name} must define env fallback resolver",
            )
            self.assertIn(
                'os.environ.get("STEP_SUMMARY_FILE", "").strip()',
                text,
                msg=f"{helper_path.name} must read STEP_SUMMARY_FILE",
            )
            self.assertIn(
                'os.environ.get("GITHUB_STEP_SUMMARY", "").strip()',
                text,
                msg=f"{helper_path.name} must fallback to GITHUB_STEP_SUMMARY",
            )
            self.assertIn(
                "def append_step_summary(path: str, text: str) -> None:",
                text,
                msg=f"{helper_path.name} must define append helper",
            )
            self.assertIn(
                "summary_path.parent.mkdir(parents=True, exist_ok=True)",
                text,
                msg=f"{helper_path.name} must create summary directory on write",
            )
            self.assertIn(
                'with summary_path.open("a", encoding="utf-8") as handle:',
                text,
                msg=f"{helper_path.name} must append summary output in utf-8 mode",
            )
            self.assertIn(
                "def write_ci_error_summary(*, source: str, phase: str, message: str) -> None:",
                text,
                msg=f"{helper_path.name} must expose shared CI error summary writer",
            )
            self.assertIn(
                "normalized = str(message).strip() or \"unknown_error\"",
                text,
                msg=f"{helper_path.name} must normalize message with unknown_error fallback",
            )
            self.assertIn(
                "step_summary_file = resolve_step_summary_file_from_env()",
                text,
                msg=f"{helper_path.name} must resolve step summary from env fallback",
            )
            self.assertIn(
                "if not step_summary_file:",
                text,
                msg=f"{helper_path.name} must no-op when summary path is empty",
            )
            self.assertIn(
                "append_step_summary(",
                text,
                msg=f"{helper_path.name} must emit summary through append helper",
            )
            self.assertIn(
                "f\"## {CI_ERROR_TITLE}\\n\\n\"",
                text,
                msg=f"{helper_path.name} must emit CI Error section title",
            )
            self.assertIn(
                "f\"- source: `{str(source).strip()}`\\n\"",
                text,
                msg=f"{helper_path.name} must emit source line",
            )
            self.assertIn(
                "f\"- phase: `{str(phase).strip()}`\\n\\n\"",
                text,
                msg=f"{helper_path.name} must emit phase line",
            )
            self.assertIn(
                "f\"```text\\n{normalized}\\n```\\n\"",
                text,
                msg=f"{helper_path.name} must wrap message in text code block",
            )

    def test_ci_shell_entry_bootstrap_report_error_updates_state(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            step_summary = tmp_path / "step_summary.md"
            proc = subprocess.run(
                [
                    "bash",
                    "-c",
                    (
                        f'source "{PROTOTYPE_DIR / "ci_shell_reporting.sh"}"; '
                        f'source "{PROTOTYPE_DIR / "ci_shell_entry.sh"}"; '
                        'ci_entry_bootstrap "demo.sh" "resolve_inputs"; '
                        'ci_entry_set_phase "write_outputs"; '
                        'ci_entry_report_error "boom detail"; '
                        'printf "%s|%s" "${CURRENT_PHASE}" "${ERROR_REPORTED}"'
                    ),
                ],
                capture_output=True,
                text=True,
                check=False,
                env={
                    **os.environ,
                    "STEP_SUMMARY_FILE": str(step_summary),
                },
            )
            if proc.returncode != 0:
                raise AssertionError(
                    f"unexpected return code: {proc.returncode}\nstdout:\n{proc.stdout}\nstderr:\n{proc.stderr}"
                )
            self.assertEqual(proc.stdout, "write_outputs|true")
            self.assertIn("[error] demo.sh: boom detail", proc.stderr)
            assert_step_summary_ci_error(
                self,
                step_summary_path=step_summary,
                source="demo.sh",
                phase="write_outputs",
                message_substring="boom detail",
            )

