    def test_python_and_shell_output_resolvers_stay_aligned(self) -> None:
        cases = (
            {
                "name": "explicit_trimmed",
                "github_output_path": "   /tmp/explicit_output.txt   ",
                "github_output": "/tmp/fallback_output.txt",
                "expected": "/tmp/explicit_output.txt",
            },
            {
                "name": "fallback_when_explicit_whitespace",
                "github_output_path": "   ",
                "github_output": "  /tmp/fallback_output.txt  ",
                "expected": "/tmp/fallback_output.txt",
            },
            {
                "name": "both_whitespace",
                "github_output_path": "   ",
                "github_output": "   ",
                "expected": "",
            },
            {
                "name": "both_empty",
                "github_output_path": "",
                "github_output": "",
                "expected": "",
            },
        )
        for case in cases:
            with self.subTest(case=case["name"]):
                env_overrides = {
                    "GITHUB_OUTPUT_PATH": case["github_output_path"],
                    "GITHUB_OUTPUT": case["github_output"],
                }
                with patch.dict(os.environ, env_overrides, clear=False):
                    python_value = resolve_github_output_file_from_env()

                proc = subprocess.run(
                    [
                        "bash",
                        "-c",
                        f'source "{PROTOTYPE_DIR / "ci_shell_reporting.sh"}"; ci_resolve_output_path',
                    ],
                    capture_output=True,
                    text=True,
                    check=False,
                    env={**os.environ, **env_overrides},
                )
                if proc.returncode != 0:
                    raise AssertionError(
                        f"unexpected return code: {proc.returncode}\nstdout:\n{proc.stdout}\nstderr:\n{proc.stderr}"
                    )
                shell_value = proc.stdout

                self.assertEqual(python_value, case["expected"])
                self.assertEqual(shell_value, case["expected"])
                self.assertEqual(python_value, shell_value)

