    def test_run_with_error_handling_emits_prefixed_error(self) -> None:
        stderr_buffer = StringIO()

        def _raise() -> int:
            raise ValueError("boom")

        with redirect_stderr(stderr_buffer):
            code = run_with_error_handling(_raise, source="demo.py")
        self.assertEqual(code, 1)
        self.assertIn("[error] demo.py: boom", stderr_buffer.getvalue())

