    def test_run_with_error_handling_writes_step_summary_when_path_provided(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            step_summary = tmp_path / "step_summary.md"

            def _raise() -> int:
                raise RuntimeError("boom")

            stderr_buffer = StringIO()
            with redirect_stderr(stderr_buffer):
                code = run_with_error_handling(
                    _raise,
                    source="demo.py",
                    step_summary_file=str(step_summary),
                    phase=PHASE_RESOLVE_INPUTS,
                )

            self.assertEqual(code, 1)
            self.assertIn("[error] demo.py: boom", stderr_buffer.getvalue())
            assert_step_summary_ci_error(
                self,
                step_summary_path=step_summary,
                source="demo.py",
                phase=PHASE_RESOLVE_INPUTS,
                message_substring="```text\nboom\n```",
            )

