    def test_run_ci_summary_run_cmd_sends_captured_stderr_to_stderr(self) -> None:
        stdout_buffer = StringIO()
        stderr_buffer = StringIO()
        with redirect_stdout(stdout_buffer), redirect_stderr(stderr_buffer):
            proc = run_ci_summary_cmd(
                [PYTHON, "-c", "import sys; print('out'); print('err', file=sys.stderr)"],
                capture_output=True,
                echo_captured_output=True,
            )
        stdout_lines = [line.strip() for line in stdout_buffer.getvalue().splitlines() if line.strip()]
        stderr_lines = [line.strip() for line in stderr_buffer.getvalue().splitlines() if line.strip()]
        self.assertEqual(proc.returncode, 0)
        self.assertIn("out", stdout_lines)
        self.assertNotIn("err", stdout_lines)
        self.assertIn("err", stderr_lines)

