    def test_append_github_output_avoids_marker_collision_in_value(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            output_path = tmp_path / "github_output.txt"
            original_marker = "CI_EOF_4242_1700000000000"
            value = f"line1\n{original_marker}\nline2"

            with patch("run_ci_pipeline.os.getpid", return_value=4242), patch(
                "run_ci_pipeline.time.time",
                return_value=1700000000.0,
            ):
                append_github_output(str(output_path), key="matrix", value=value)

            lines = output_path.read_text(encoding="utf-8").splitlines()
            self.assertEqual(len(lines), 5)
            self.assertEqual(lines[0], f"matrix<<{original_marker}_X")
            self.assertEqual(lines[1], "line1")
            self.assertEqual(lines[2], original_marker)
            self.assertEqual(lines[3], "line2")
            self.assertEqual(lines[4], f"{original_marker}_X")

    def test_python_and_shell_github_output_writers_stay_aligned(self) -> None:
        cases = (
            {
                "name": "single_line",
                "key": "alpha",
                "value": "beta",
                "expected_value": "beta",
            },
            {
                "name": "multiline",
                "key": "alpha",
                "value": "line1\nline2",
                "expected_value": "line1\nline2",
            },
            {
                "name": "multiline_trailing_newline",
                "key": "alpha",
                "value": "line1\nline2\n",
                "expected_value": "line1\nline2",
            },
            {
                "name": "multiline_marker_like_text",
                "key": "alpha",
                "value": "line1\nCI_EOF_DEMO\nline2",
                "expected_value": "line1\nCI_EOF_DEMO\nline2",
            },
        )
        for case in cases:
            with self.subTest(case=case["name"]):
                with tempfile.TemporaryDirectory() as tmp:
                    tmp_path = Path(tmp)
                    py_output = tmp_path / "py_output.txt"
                    sh_output = tmp_path / "sh_output.txt"

                    append_github_output(str(py_output), key=case["key"], value=case["value"])
                    proc = subprocess.run(
                        [
                            "bash",
                            "-c",
                            (
                                f'source "{PROTOTYPE_DIR / "ci_shell_reporting.sh"}"; '
                                f'ci_write_output "{sh_output}" "{case["key"]}" "${{VALUE}}"'
                            ),
                        ],
                        capture_output=True,
                        text=True,
                        check=False,
                        env={**os.environ, "VALUE": case["value"]},
                    )
                    if proc.returncode != 0:
                        raise AssertionError(
                            f"unexpected return code: {proc.returncode}\nstdout:\n{proc.stdout}\nstderr:\n{proc.stderr}"
                        )

                    py_entries = parse_github_output_entries(py_output)
                    sh_entries = parse_github_output_entries(sh_output)
                    expected_entries = [(case["key"], case["expected_value"])]
                    self.assertEqual(py_entries, expected_entries)
                    self.assertEqual(sh_entries, expected_entries)
                    self.assertEqual(py_entries, sh_entries)

    def test_python_and_shell_github_output_writers_keep_append_order(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            py_output = tmp_path / "py_output.txt"
            sh_output = tmp_path / "sh_output.txt"

            append_github_output(str(py_output), key="release_id", value="REL_TEST_001")
            append_github_output(str(py_output), key="manifest_path", value="line1\nline2\n")

            proc = subprocess.run(
                [
                    "bash",
                    "-c",
                    (
                        f'source "{PROTOTYPE_DIR / "ci_shell_reporting.sh"}"; '
                        f'ci_write_output "{sh_output}" "release_id" "${{VALUE1}}"; '
                        f'ci_write_output "{sh_output}" "manifest_path" "${{VALUE2}}"'
                    ),
                ],
                capture_output=True,
                text=True,
                check=False,
                env={
                    **os.environ,
                    "VALUE1": "REL_TEST_001",
                    "VALUE2": "line1\nline2\n",
                },
            )
            if proc.returncode != 0:
                raise AssertionError(
                    f"unexpected return code: {proc.returncode}\nstdout:\n{proc.stdout}\nstderr:\n{proc.stderr}"
                )

            expected_entries = [
                ("release_id", "REL_TEST_001"),
                ("manifest_path", "line1\nline2"),
            ]
            py_entries = parse_github_output_entries(py_output)
            sh_entries = parse_github_output_entries(sh_output)
            self.assertEqual(py_entries, expected_entries)
            self.assertEqual(sh_entries, expected_entries)
            self.assertEqual(py_entries, sh_entries)

