    def test_runtime_available_workflow_dispatch_mapping_covers_workflow_dispatch_inputs(self) -> None:
        workflow_path = PROTOTYPE_DIR.parents[2] / ".github" / "workflows" / "e2e-runtime-available.yml"
        workflow_text = workflow_path.read_text(encoding="utf-8")
        dispatch_script_text = (PROTOTYPE_DIR / "run_runtime_available_workflow_dispatch.sh").read_text(
            encoding="utf-8"
        )
        workflow_dispatch_start = workflow_text.find("workflow_dispatch:")
        self.assertNotEqual(workflow_dispatch_start, -1)
        workflow_dispatch_block = workflow_text[workflow_dispatch_start:]
        permissions_start = workflow_dispatch_block.find("\npermissions:")
        if permissions_start != -1:
            workflow_dispatch_block = workflow_dispatch_block[:permissions_start]
        workflow_inputs = set(re.findall(r"^\s{6}([a-z0-9_]+):\s*$", workflow_dispatch_block, flags=re.M))
        dispatch_mapping_inputs = set(
            re.findall(r'\("([a-z0-9_]+)",\s*"INPUT_[A-Z0-9_]+"\)', dispatch_script_text)
        )
        missing = sorted(workflow_inputs - dispatch_mapping_inputs)
        extra = sorted(dispatch_mapping_inputs - workflow_inputs)
        self.assertEqual(missing, [], msg=f"dispatch mapping missing workflow inputs: {missing}")
        self.assertEqual(extra, [], msg=f"dispatch mapping has unknown workflow inputs: {extra}")

