    def test_emit_ci_error_includes_details(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            step_summary = tmp_path / "step_summary.md"
            stderr_buffer = StringIO()
            with redirect_stderr(stderr_buffer):
                emit_ci_error(
                    step_summary_file=str(step_summary),
                    source="run_ci_pipeline.py",
                    message="pipeline command failed with exit code 2",
                    details={
                        "exit_code": "2",
                        "log_path": "/tmp/e2e_pipeline.log",
                    },
                )

            self.assertIn("[error] run_ci_pipeline.py: pipeline command failed with exit code 2", stderr_buffer.getvalue())
            assert_summary_markdown_contains(
                self,
                step_summary_path=step_summary,
                expected_substrings=[
                    "## E2E CI Error",
                    "- source: `run_ci_pipeline.py`",
                    "- exit_code: `2`",
                    "- log_path: `/tmp/e2e_pipeline.log`",
                ],
            )

    def test_emit_ci_error_uses_whitelisted_detail_order(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            step_summary = tmp_path / "step_summary.md"
            with redirect_stderr(StringIO()):
                emit_ci_error(
                    step_summary_file=str(step_summary),
                    source="run_ci_summary.py",
                    message="failed",
                    details={
                        "log_path": "/tmp/a.log",
                        "phase": "send_notification",
                        "unknown_key": "SHOULD_NOT_APPEAR",
                        "exit_code": "12",
                    },
                )

            summary = assert_summary_markdown_contains(
                self,
                step_summary_path=step_summary,
                expected_substrings=[
                    "- phase: `send_notification`",
                    "- exit_code: `12`",
                    "- log_path: `/tmp/a.log`",
                ],
                forbidden_substrings=["unknown_key"],
            )
            phase_index = summary.find("- phase: `send_notification`")
            exit_index = summary.find("- exit_code: `12`")
            log_index = summary.find("- log_path: `/tmp/a.log`")
            self.assertGreaterEqual(phase_index, 0)
            self.assertGreaterEqual(exit_index, 0)
            self.assertGreaterEqual(log_index, 0)
            self.assertLess(phase_index, exit_index)
            self.assertLess(exit_index, log_index)
            self.assertEqual(CI_ERROR_DETAIL_ORDER[:3], ("phase", "command", "exit_code"))

