    def test_summary_entry_runtime_available_profile_enables_rn2_hold_gates_by_default(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            release_prefix = "REL_SUMMARY_ENTRY_RUNTIME_AVAILABLE_RN2_DEFAULT_GATE_001"
            artifacts_root = tmp_path / "artifacts"
            reports_root = artifacts_root / "reports"
            batch_root = artifacts_root / "batch_rn2"
            reports_root.mkdir(parents=True, exist_ok=True)
            batch_root.mkdir(parents=True, exist_ok=True)

            (reports_root / f"{release_prefix}_sds_v0.1.0.summary.json").write_text(
                json.dumps(
                    {
                        "release_id": f"{release_prefix}_sds_v0_1_0",
                        "sds_version": "sds_v0.1.0",
                        "final_result": "PASS",
                        "generated_at": "2026-01-01T00:00:00+00:00",
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            (reports_root / f"{release_prefix}_runtime_native_both_evidence_compare.json").write_text(
                json.dumps(
                    {
                        "schema_version": "runtime_evidence_compare_v0",
                        "left": {
                            "label": "carla",
                            "path": str(reports_root / f"{release_prefix}_carla_runtime_available_evidence.json"),
                            "summary": {
                                "release_prefix": release_prefix,
                                "sim_runtime": "carla",
                            },
                        },
                        "right": {
                            "label": "awsim",
                            "path": str(reports_root / f"{release_prefix}_awsim_runtime_available_evidence.json"),
                            "summary": {
                                "release_prefix": release_prefix,
                                "sim_runtime": "awsim",
                            },
                        },
                        "diff": {
                            "top_level_mismatches": {
                                "sim_runtime": {"left": "carla", "right": "awsim"},
                            },
                            "status_count_diffs": {},
                            "runtime_count_diffs": {},
                            "interop_import_status_count_diffs": {},
                            "interop_import_manifest_consistency_diffs": {},
                            "interop_import_manifest_mode_count_diffs": {
                                "allow": {"left": 1, "right": 0, "delta": -1},
                            },
                            "interop_import_export_mode_count_diffs": {},
                            "interop_import_require_manifest_input_count_diffs": {},
                            "interop_import_require_export_input_count_diffs": {},
                            "interop_import_profile_diffs": [],
                            "profile_presence": {
                                "left_only": [],
                                "right_only": [],
                                "shared_count": 0,
                            },
                            "profile_diffs": [],
                        },
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            for batch_idx in (1, 2, 3):
                batch_id = f"BATCH_RUNTIME_AVAILABLE_RN2_{batch_idx:03d}"
                batch_dir = batch_root / batch_id.lower()
                batch_dir.mkdir(parents=True, exist_ok=True)
                log_replay_manifest = batch_dir / "log_replay_manifest.json"
                log_replay_summary = batch_dir / "log_replay_summary.json"
                log_replay_summary.write_text(
                    json.dumps({"status": "fail"}) + "\n",
                    encoding="utf-8",
                )
                log_replay_manifest.write_text(
                    json.dumps(
                        {
                            "status": "fail",
                            "summary_path": str(log_replay_summary.name),
                            "log_id": f"LOG_RUNTIME_AVAILABLE_{batch_idx:03d}",
                        }
                    )
                    + "\n",
                    encoding="utf-8",
                )
                (batch_dir / "pipeline_result.json").write_text(
                    json.dumps(
                        {
                            "release_id": f"{release_prefix}_sds_v0_1_0",
                            "batch_id": batch_id,
                            "overall_result": "PASS",
                            "strict_gate": True,
                            "trend_gate": {"result": "PASS"},
                            "reports": [{"sds_version": "sds_v0.1.0"}],
                            "phase2_hooks": {
                                "enabled": True,
                                "log_replay_manifest_path": str(log_replay_manifest.name),
                            },
                        }
                    )
                    + "\n",
                    encoding="utf-8",
                )

            out_text = tmp_path / "summary.txt"
            out_json = tmp_path / "summary.json"
            out_db = tmp_path / "summary.sqlite"
            notification_out = tmp_path / "notification.json"
            step_summary = tmp_path / "step_summary.md"
            proc = subprocess.run(
                ["bash", str(PROTOTYPE_DIR / "run_ci_summary_entry.sh")],
                capture_output=True,
                text=True,
                check=False,
                cwd=str(tmp_path),
                env={
                    **os.environ,
                    "CI_SUMMARY_PROFILE": "runtime_available",
                    "RELEASE_PREFIX": release_prefix,
                    "ARTIFACTS_ROOT": str(artifacts_root),
                    "SUMMARY_FILES_SUBPATH": "reports",
                    "PIPELINE_MANIFESTS_SUBPATH": "batch_rn2",
                    "SUMMARY_OUT_TEXT": str(out_text),
                    "SUMMARY_OUT_JSON": str(out_json),
                    "SUMMARY_OUT_DB": str(out_db),
                    "SUMMARY_TITLE": "Runtime Available RN2 Default Gate",
                    "WORKFLOW_NAME": "Runtime Available",
                    "NOTIFICATION_OUT_JSON": str(notification_out),
                    "NOTIFY_RUNTIME_EVIDENCE_COMPARE_HOLD_MIN_ARTIFACTS_WITH_DIFFS": "1",
                    "STEP_SUMMARY_FILE": str(step_summary),
                },
            )
            self.assertEqual(proc.returncode, 1)
            self.assertIn(
                "[error] run_ci_summary.py: phase2 log replay threshold drift hold policy failed: severity=HOLD",
                proc.stderr,
            )
            self.assertIn(
                "runtime native smoke threshold drift hold policy failed: severity=HOLD",
                proc.stderr,
            )
            self.assertIn(
                "runtime native evidence compare threshold drift hold policy failed: severity=HOLD",
                proc.stderr,
            )
            self.assertNotIn("[error] run_ci_summary_entry.sh:", proc.stderr)
            self.assertTrue(out_json.exists())
            self.assertTrue(notification_out.exists())
            summary_payload = read_json_file(self, file_path=out_json)
            self.assertEqual(
                summary_payload.get("threshold_drift_hold_policy_failure_scope_counts"),
                {
                    "phase2_log_replay": 1,
                    "runtime_native_smoke": 1,
                    "runtime_native_evidence_compare": 1,
                },
            )
            assert_step_summary_ci_error(
                self,
                step_summary_path=step_summary,
                source="run_ci_summary.py",
                phase=SUMMARY_PHASE_BUILD_NOTIFICATION_PAYLOAD,
                message_substring="phase2 log replay threshold drift hold policy failed: severity=HOLD",
            )
            self.assertIn(
                "runtime native smoke threshold drift hold policy failed: severity=HOLD",
                step_summary.read_text(encoding="utf-8"),
            )
            self.assertIn(
                "runtime native evidence compare threshold drift hold policy failed: severity=HOLD",
                step_summary.read_text(encoding="utf-8"),
            )

