    def test_summary_entry_prefers_step_summary_file_over_github_step_summary(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            explicit_summary = tmp_path / "explicit_summary.md"
            fallback_summary = tmp_path / "fallback_summary.md"
            proc = subprocess.run(
                ["bash", str(PROTOTYPE_DIR / "run_ci_summary_entry.sh")],
                capture_output=True,
                text=True,
                check=False,
                cwd=str(tmp_path),
                env={
                    **os.environ,
                    "CI_SUMMARY_DRY_RUN": "true",
                    "RELEASE_PREFIX": "REL_SUMMARY_ENTRY_002",
                    "NOTIFY_ON": "sometimes",
                    "STEP_SUMMARY_FILE": str(explicit_summary),
                    "GITHUB_STEP_SUMMARY": str(fallback_summary),
                },
            )
            self.assertEqual(proc.returncode, 1)
            self.assertIn(
                "[error] run_ci_summary_entry.sh: NOTIFY_ON must be one of: always hold warn hold_warn pass never",
                proc.stderr,
            )
            self.assertNotIn("[error] run_ci_summary.py:", proc.stderr)
            self.assertFalse(fallback_summary.exists())
            summary_text = assert_summary_markdown_contains(
                self,
                step_summary_path=explicit_summary,
                expected_substrings=[
                    "## E2E CI Error",
                    "- source: `run_ci_summary_entry.sh`",
                ],
            )
            self.assertEqual(summary_text.count("## E2E CI Error"), 1)
            self.assertNotIn("- source: `run_ci_summary.py`", summary_text)

