    def test_summary_entry_trims_optional_notify_history_inputs_before_forwarding(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            proc = subprocess.run(
                ["bash", str(PROTOTYPE_DIR / "run_ci_summary_entry.sh")],
                capture_output=True,
                text=True,
                check=False,
                cwd=str(tmp_path),
                env={
                    **os.environ,
                    "CI_SUMMARY_DRY_RUN": "true",
                    "RELEASE_PREFIX": "REL_SUMMARY_ENTRY_OUTLIER_TRIM_001",
                    "NOTIFICATION_OUT_JSON": str(tmp_path / "notify.json"),
                    "SUMMARY_FILES_ROOT": f"  {tmp_path / 'summary_root'}  ",
                    "PIPELINE_MANIFESTS_ROOT": f"  {tmp_path / 'manifest_root'}  ",
                    "NOTIFY_TIMING_REGRESSION_BASELINE_MS": " 100000 ",
                    "NOTIFY_TIMING_REGRESSION_WARN_RATIO": " 0.2 ",
                    "NOTIFY_TIMING_REGRESSION_HISTORY_WINDOW": " 5 ",
                    "NOTIFY_TIMING_REGRESSION_HISTORY_DIR": f"  {tmp_path / 'history_root'}  ",
                    "NOTIFY_TIMING_REGRESSION_HISTORY_OUTLIER_METHOD": "  iqr  ",
                    "NOTIFY_TIMING_REGRESSION_HISTORY_TRIM_RATIO": " 0.1 ",
                },
            )
            if proc.returncode != 0:
                raise AssertionError(
                    f"unexpected return code: {proc.returncode}\nstdout:\n{proc.stdout}\nstderr:\n{proc.stderr}"
                )
            summary_root = (tmp_path / "summary_root").resolve()
            manifest_root = (tmp_path / "manifest_root").resolve()
            history_root = (tmp_path / "history_root").resolve()
            self.assertIn(f"--summary-files-root {summary_root}", proc.stdout)
            self.assertIn(f"--pipeline-manifests-root {manifest_root}", proc.stdout)
            self.assertIn("--timing-regression-baseline-ms 100000", proc.stdout)
            self.assertIn("--timing-regression-warn-ratio 0.2", proc.stdout)
            self.assertIn("--timing-regression-history-window 5", proc.stdout)
            self.assertIn(f"--timing-regression-history-dir {history_root}", proc.stdout)
            self.assertIn("--timing-regression-history-outlier-method iqr", proc.stdout)
            self.assertIn("--timing-regression-history-trim-ratio 0.1", proc.stdout)

