    def test_precheck_entry_detects_shell_file_change(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            repo_dir = tmp_path / "repo"
            repo_dir.mkdir(parents=True, exist_ok=True)

            git_run(repo_dir, "init")
            tracked_file = repo_dir / "30_Projects" / "P_E2E_Stack" / "prototype" / "placeholder.txt"
            tracked_file.parent.mkdir(parents=True, exist_ok=True)
            tracked_file.write_text("base\n", encoding="utf-8")
            base_sha = git_commit_all(repo_dir, "base")

            changed_shell = repo_dir / "30_Projects" / "P_E2E_Stack" / "prototype" / "new_entry.sh"
            changed_shell.write_text("#!/usr/bin/env bash\necho hi\n", encoding="utf-8")
            head_sha = git_commit_all(repo_dir, "shell change")

            github_output = tmp_path / "github_output.txt"
            proc = subprocess.run(
                ["bash", str(PROTOTYPE_DIR / "run_ci_precheck_entry.sh")],
                capture_output=True,
                text=True,
                check=False,
                cwd=str(repo_dir),
                env={
                    **os.environ,
                    "EVENT_NAME": "pull_request",
                    "BASE_SHA": base_sha,
                    "HEAD_SHA": head_sha,
                    "GITHUB_OUTPUT_PATH": str(github_output),
                },
            )
            if proc.returncode != 0:
                raise AssertionError(
                    f"unexpected return code: {proc.returncode}\nstdout:\n{proc.stdout}\nstderr:\n{proc.stderr}"
                )
            assert_github_output_contains(
                self,
                output_path=github_output,
                expected_substrings=[
                    "should_run=true",
                    "reason=runtime_inputs_changed",
                    "matched_file=30_Projects/P_E2E_Stack/prototype/new_entry.sh",
                    "matched_pattern=^30_Projects/P_E2E_Stack/prototype/.*\\.(py|sh|json|yaml|yml)$",
                ],
            )

