            matrix_line = next(line for line in output_text.splitlines() if line.startswith("matrix="))
            matrix = read_json_text(self, text=matrix_line.split("=", 1)[1])
            include = matrix.get("include", [])
            self.assertEqual(len(include), 1)
            self.assertEqual(include[0].get("profile_id"), "beta")

