class RunCiPipelineTests(unittest.TestCase):
    def test_dry_run_writes_github_output_and_uses_defaults(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            github_output = tmp_path / "github_output.txt"

            proc = run_script(
                PROTOTYPE_DIR / "run_ci_pipeline.py",
                "--batch-spec",
                "30_Projects/P_Cloud-Engine/prototype/examples/batch_smoke_v0.json",
                "--release-id",
                "REL_TEST_DRYRUN_001",
                "--runner",
                str(PROTOTYPE_DIR / "run_e2e_pipeline.py"),
                "--strict-gate-default",
                "true",
                "--sds-versions-csv",
                "sds_v0.1.0, sds_v0.2.0",
                "--github-output",
                str(github_output),
                "--dry-run",
            )

            self.assertIn("[ok] dry-run=true", proc.stdout)
            self.assertIn("--strict-gate", proc.stdout)
            self.assertIn("--sds-version sds_v0.1.0", proc.stdout)
            self.assertIn("--sds-version sds_v0.2.0", proc.stdout)

            assert_github_output_contains(
                self,
                output_path=github_output,
                expected_substrings=[
                    "release_id=REL_TEST_DRYRUN_001",
                    "manifest_path=",
                ],
            )

