            tmp_path = Path(tmp)
            explicit_output = tmp_path / "explicit_output.txt"
            fallback_output = tmp_path / "fallback_output.txt"
            proc = subprocess.run(
                [
                    PYTHON,
                    str(PROTOTYPE_DIR / "run_ci_pipeline.py"),
                    "--batch-spec",
                    "30_Projects/P_Cloud-Engine/prototype/examples/batch_smoke_v0.json",
                    "--release-id",
                    "REL_TEST_DRYRUN_ENV_OUTPUT_003",
                    "--runner",
                    str(PROTOTYPE_DIR / "run_e2e_pipeline.py"),
                    "--github-output",
                    str(explicit_output),
                    "--dry-run",
                ],
                capture_output=True,
                text=True,
                check=False,
                env={**os.environ, "GITHUB_OUTPUT_PATH": str(fallback_output)},
            )
            if proc.returncode != 0:
                raise AssertionError(
                    f"unexpected return code: {proc.returncode}\nstdout:\n{proc.stdout}\nstderr:\n{proc.stderr}"
                )
            self.assertFalse(fallback_output.exists())
            assert_github_output_contains(
                self,
                output_path=explicit_output,
                expected_substrings=[
                    "release_id=REL_TEST_DRYRUN_ENV_OUTPUT_003",
                    "manifest_path=",
                ],
            )

