    def test_phase4_duplicate_linkage_modules_are_rejected(self) -> None:
        proc = run_script(
            PROTOTYPE_DIR / "run_ci_pipeline.py",
            "--batch-spec",
            "batch.json",
            "--release-id",
            "REL_TEST_PHASE4_DUPLICATE_MODULES_001",
            "--phase4-enable-hooks-input",
            "true",
            "--phase4-linkage-module",
            "adp",
            "--phase4-linkage-module",
            "adp",
            "--dry-run",
            expected_rc=1,
        )
        self.assertIn(
            "[error] run_ci_pipeline.py: phase4-linkage-module contains duplicate entries: adp",
            proc.stderr,
        )
        self.assertNotIn("Traceback", proc.stderr)

