    def test_profile_resolution_failure_warns_and_uses_fallback(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            profiles_path = tmp_path / "profiles.json"
            profiles_path.write_text(
                json.dumps(
                    {
                        "profiles": [
                            {
                                "profile_id": "quick",
                                "default_batch_spec": "from_profile.json",
                                "default_sds_versions": "sds_profile_v1,sds_profile_v2",
                            }
                        ]
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            loader_path = tmp_path / "failing_loader.py"
            loader_path.write_text(
                "import sys\n"
                "print('loader exploded', file=sys.stderr)\n"
                "sys.exit(7)\n",
                encoding="utf-8",
            )

            proc = run_script(
                PROTOTYPE_DIR / "run_ci_pipeline.py",
                "--release-id",
                "REL_TEST_DRYRUN_004A",
                "--runner",
                str(PROTOTYPE_DIR / "run_e2e_pipeline.py"),
                "--profile-file",
                str(profiles_path),
                "--profile-id",
                "quick",
                "--profile-loader",
                str(loader_path),
                "--fallback-batch-spec",
                "smoke.json",
                "--dry-run",
            )
            self.assertIn("[warn] profile resolution failed with exit code 7", proc.stderr)
            self.assertIn(str(loader_path.resolve()), proc.stderr)
            self.assertIn("loader exploded", proc.stderr)
            self.assertNotIn("[warn] profile resolution failed with exit code 7", proc.stdout)
            self.assertNotIn("loader exploded", proc.stdout)
            self.assertIn("--batch-spec smoke.json", proc.stdout)

