class GenerateBatchFromCatalogTests(unittest.TestCase):
    def test_generates_batch_spec_with_numeric_overrides(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            catalog_manifest = tmp_path / "catalog_manifest.json"
            scenarios_dir = tmp_path / "scenarios"
            scenarios_dir.mkdir(parents=True, exist_ok=True)
            (scenarios_dir / "s1.json").write_text("{}\n", encoding="utf-8")
            (scenarios_dir / "s2.json").write_text("{}\n", encoding="utf-8")
            catalog_manifest.write_text(
                json.dumps(
                    {
                        "scenarios": [
                            {"scenario_file": "scenarios/s1.json"},
                            {"scenario_file": "scenarios/s2.json"},
                        ]
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            out_path = tmp_path / "batch_spec.json"

            proc = run_script(
                PROTOTYPE_DIR / "../../P_Cloud-Engine/prototype/generate_batch_from_catalog.py",
                "--catalog-manifest",
                str(catalog_manifest),
                "--batch-id",
                "BATCH_GEN_001",
                "--sds-version",
                "sds_v0.1.0",
                "--out",
                str(out_path),
                "--run-id-start",
                "5",
                "--seed-base",
                "500",
                "--seed-step",
                "7",
                "--max-concurrency",
                "6",
                "--timeout-sec-per-run",
                "45",
            )
            self.assertIn("[ok] run_count=2", proc.stdout)
            self.assertTrue(out_path.exists())

            payload = read_json_file(self, file_path=out_path)
            self.assertEqual(payload.get("batch_id"), "BATCH_GEN_001")
            self.assertEqual(payload.get("defaults", {}).get("seed"), 500)
            self.assertEqual(payload.get("execution", {}).get("max_concurrency"), 6)
            self.assertEqual(payload.get("execution", {}).get("timeout_sec_per_run"), 45)
            runs = payload.get("runs", [])
            self.assertEqual(len(runs), 2)
            self.assertEqual(runs[0].get("run_id"), "RUN_RG_0005")
            self.assertEqual(runs[0].get("seed"), 500)
            self.assertEqual(runs[1].get("run_id"), "RUN_RG_0006")
            self.assertEqual(runs[1].get("seed"), 507)

