class RunE2EPipelineTests(unittest.TestCase):
    def _write_phase4_success_cloud_runner_script(
        self,
        path: Path,
        *,
        run_id: str,
        scenario_id: str,
        sds_version: str = "sds_v1",
    ) -> None:
        path.write_text(
            "import json\n"
            "import sys\n"
            "from pathlib import Path\n"
            "spec_path = Path(sys.argv[sys.argv.index('--batch-spec') + 1]).resolve()\n"
            "spec = json.loads(spec_path.read_text(encoding='utf-8'))\n"
            "output_root = Path(spec.get('output_root')).resolve()\n"
            "batch_root = output_root / str(spec.get('batch_id'))\n"
            "batch_root.mkdir(parents=True, exist_ok=True)\n"
            "result_path = batch_root / 'batch_result.json'\n"
            "result_path.write_text(json.dumps({'ok': True}) + '\\n', encoding='utf-8')\n"
            f"run_dir = batch_root / {run_id!r}\n"
            "run_dir.mkdir(parents=True, exist_ok=True)\n"
            "(run_dir / 'summary.json').write_text(json.dumps({\n"
            f"  'run_id': {run_id!r},\n"
            f"  'scenario_id': {scenario_id!r},\n"
            f"  'sds_version': {sds_version!r},\n"
            "  'status': 'success'\n"
            "}) + '\\n', encoding='utf-8')\n"
            "print(f'[ok] result={result_path}')\n",
            encoding="utf-8",
        )

    def _write_report_runner_script(self, path: Path, *, final_result: str = "PASS") -> None:
        path.write_text(
            "import json\n"
            "import sys\n"
            "from pathlib import Path\n"
            "args = sys.argv\n"
            "release_id = args[args.index('--release-id') + 1]\n"
            "sds_version = args[args.index('--sds-version') + 1]\n"
            "out_path = Path(args[args.index('--out') + 1]).resolve()\n"
            "summary_path = Path(args[args.index('--summary-out') + 1]).resolve()\n"
            "out_path.parent.mkdir(parents=True, exist_ok=True)\n"
            "summary_path.parent.mkdir(parents=True, exist_ok=True)\n"
            "out_path.write_text('# fake report\\n', encoding='utf-8')\n"
            "summary_path.write_text(json.dumps({\n"
            "  'release_id': release_id,\n"
            "  'sds_version': sds_version,\n"
            f"  'final_result': {final_result!r}\n"
            "}) + '\\n', encoding='utf-8')\n"
            "sys.exit(0)\n",
            encoding="utf-8",
        )

    def _write_phase4_hil_fixture(self, tmp_path: Path, *, scenario_id: str) -> tuple[Path, Path]:
        hil_interface = tmp_path / "phase4" / "hil_interface.json"
        hil_sequence = tmp_path / "phase4" / "hil_sequence.json"
        hil_interface.parent.mkdir(parents=True, exist_ok=True)
        hil_interface.write_text(
            json.dumps(
                {
                    "interface_schema_version": "hil_interface_v0",
                    "channels": [
                        {
                            "channel_id": "steering_cmd",
                            "direction": "sim_to_hil",
                            "signal_type": "float",
                        }
                    ],
                }
            )
            + "\n",
            encoding="utf-8",
        )
        hil_sequence.write_text(
            json.dumps(
                {
                    "sequence_schema_version": "hil_test_sequence_v0",
                    "scenario_id": scenario_id,
                    "steps": [
                        {
                            "step_id": "step_001",
                            "trigger": {
                                "trigger_type": "time_offset_sec",
                                "trigger_value": 0.0,
                            },
                            "action": {
                                "target_channel_id": "steering_cmd",
                                "value": 0.1,
                            },
                            "duration_sec": 1.0,
                        }
                    ],
                }
            )
            + "\n",
            encoding="utf-8",
        )
        return hil_interface, hil_sequence

    def test_dry_run_forwards_subprocess_stderr_to_stderr(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            batch_spec_path = tmp_path / "batch_spec.json"
            batch_spec_path.write_text(json.dumps({"batch_id": "batch_demo"}) + "\n", encoding="utf-8")
            runner_path = tmp_path / "runner.py"
            runner_path.write_text(
                "import sys\n"
                "print('cloud ok stdout')\n"
                "print('cloud warn stderr', file=sys.stderr)\n"
                "sys.exit(0)\n",
                encoding="utf-8",
            )

            proc = run_script(
                PROTOTYPE_DIR / "run_e2e_pipeline.py",
                "--batch-spec",
                str(batch_spec_path),
                "--release-id",
                "REL_E2E_DRYRUN_STDERR_001",
                "--cloud-runner",
                str(runner_path),
                "--dry-run",
            )

            self.assertIn("cloud ok stdout", proc.stdout)
            self.assertIn("cloud warn stderr", proc.stderr)
            self.assertNotIn("cloud warn stderr", proc.stdout)

    def test_dry_run_missing_cloud_runner_includes_failure_detail(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            batch_spec_path = tmp_path / "batch_spec.json"
            batch_spec_path.write_text(json.dumps({"batch_id": "batch_demo"}) + "\n", encoding="utf-8")
            missing_runner = tmp_path / "missing_cloud_runner.py"

            proc = run_script(
                PROTOTYPE_DIR / "run_e2e_pipeline.py",
                "--batch-spec",
                str(batch_spec_path),
                "--release-id",
                "REL_E2E_FAIL_001",
                "--cloud-runner",
                str(missing_runner),
                "--dry-run",
                expected_rc=1,
            )

            combined = f"{proc.stdout}\n{proc.stderr}"
            self.assertIn("command failed with exit code", combined)
            self.assertIn(str(missing_runner), combined)
            self.assertIn("can't open file", combined)
            self.assertIn("[error] run_e2e_pipeline.py:", proc.stderr)
            self.assertNotIn("Traceback", proc.stderr)

