            self.assertEqual(proc.returncode, 1)
            self.assertIn("[error] run_e2e_pipeline.py:", proc.stderr)
            self.assertIn("command failed with exit code", proc.stderr)
            assert_step_summary_ci_error(
                self,
                step_summary_path=step_summary,
                source="run_e2e_pipeline.py",
                phase=PIPELINE_PHASE_RUN_PIPELINE,
                message_substring="command failed with exit code",
            )

