            self.assertIn("[error] strict_gate enabled and release/trend gate is HOLD", proc.stderr)
            self.assertNotIn("[error] strict_gate enabled and release/trend gate is HOLD", proc.stdout)

            manifest_path = tmp_path / "batch_runs" / "batch_demo" / "pipeline_result.json"
