    def test_phase2_route_quality_gate_holds_when_routing_semantic_pass_is_required(self) -> None:
        result, reasons, details = evaluate_phase2_route_quality_gate(
            phase2_enable_hooks=True,
            phase2_hooks={
                "map_route_status": "pass",
                "map_route_lane_count": 4,
                "map_route_total_length_m": 120.0,
                "map_validate_routing_semantic_status": "warn",
                "map_validate_routing_semantic_warning_count": 2,
                "map_validate_unreachable_lane_count": 1,
                "map_validate_non_reciprocal_link_warning_count": 1,
                "map_validate_continuity_gap_warning_count": 0,
            },
            require_status_pass=True,
            require_routing_semantic_pass=True,
            min_lane_count=1,
            min_total_length_m=1.0,
            max_routing_semantic_warning_count=0,
            max_unreachable_lane_count=0,
            max_non_reciprocal_link_warning_count=0,
            max_continuity_gap_warning_count=0,
        )
        self.assertEqual(result, "HOLD")
        self.assertIn("phase2_map_validate_routing_semantic_status warn != pass", reasons)
        self.assertEqual(str(details.get("observed_routing_semantic_status", "")), "warn")
        self.assertEqual(int(details.get("observed_routing_semantic_warning_count", 0) or 0), 2)

