            self.assertEqual(str(phase2_hooks.get("sensor_sweep_fidelity_tier", "")), "contract")
            self.assertEqual(int(phase2_hooks.get("sensor_sweep_candidate_count", 0) or 0), 2)
            self.assertEqual(str(phase2_hooks.get("sensor_sweep_best_rig_id", "")), "rig_high")
