            self.assertIn("camera_gain_db_avg", phase2_sensor_quality_summary)
            self.assertIn("camera_bloom_halo_strength_avg", phase2_sensor_quality_summary)
            self.assertIn("camera_bloom_level_counts", phase2_sensor_quality_summary)
            self.assertIn("camera_depth_enabled_frame_count", phase2_sensor_quality_summary)
            self.assertIn("camera_depth_mode_counts", phase2_sensor_quality_summary)
            self.assertIn("camera_optical_flow_enabled_frame_count", phase2_sensor_quality_summary)
            self.assertIn("camera_optical_flow_velocity_direction_counts", phase2_sensor_quality_summary)
            self.assertIn("lidar_detection_ratio_avg", phase2_sensor_quality_summary)
            self.assertIn("radar_ghost_target_count_total", phase2_sensor_quality_summary)
            self.assertTrue(sensor_out.exists())
            self.assertTrue(sensor_sweep_out.exists())
            self.assertTrue(map_canonical.exists())
            self.assertTrue(map_validate_report.exists())
            self.assertTrue(map_route_report.exists())

            sensor_payload = read_json_file(self, file_path=sensor_out)
            self.assertEqual(sensor_payload.get("frame_count"), 3)

            log_replay_manifest_path = Path(str(phase2_hooks.get("log_replay_manifest_path", "")))
            self.assertTrue(log_replay_manifest_path.exists())
            replay_manifest = read_json_file(self, file_path=log_replay_manifest_path)
            self.assertEqual(replay_manifest.get("log_id"), "LOG_REAL_HOOK_001")
            self.assertIn("REL_PHASE2_REAL_001_LOG_REPLAY", str(replay_manifest.get("run_id")))

            map_validation_payload = read_json_file(self, file_path=map_validate_report)
            self.assertEqual(map_validation_payload.get("error_count"), 0)
            map_route_payload = read_json_file(self, file_path=map_route_report)
            self.assertEqual(map_route_payload.get("route_status"), "pass")
            self.assertEqual(map_route_payload.get("route_lane_ids"), ["lane_a"])
            self.assertEqual(map_route_payload.get("route_cost_mode"), "length")

