    def test_fail_on_runtime_threshold_drift_hold_reports_policy_error(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            release_prefix = "REL_TEST_SUMMARY_DRIFT_GATE_001"
            artifacts_root = tmp_path / "artifacts"
            reports_root = artifacts_root / "reports"
            reports_root.mkdir(parents=True, exist_ok=True)

            (reports_root / f"{release_prefix}_sds_v0.1.0.summary.json").write_text(
                json.dumps(
                    {
                        "release_id": f"{release_prefix}_sds_v0_1_0",
                        "sds_version": "sds_v0.1.0",
                        "final_result": "PASS",
                        "generated_at": "2026-01-01T00:00:00+00:00",
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            (reports_root / f"{release_prefix}_runtime_lane_execution_summary.json").write_text(
                json.dumps(
                    {
                        "schema_version": "runtime_lane_execution_summary_v0",
                        "release_prefix": release_prefix,
                        "lane_input": "auto",
                        "lane_resolved": "exec",
                        "runner_platform": "Linux/x86_64",
                        "sim_runtime_input": "both",
                        "runtime_exec_lane_warn_min_rows": 2,
                        "runtime_exec_lane_hold_min_rows": 0,
                        "runtime_compare_warn_min_artifacts_with_diffs": 0,
                        "runtime_compare_hold_min_artifacts_with_diffs": 0,
                        "runtime_rows": [
                            {
                                "runtime": "awsim",
                                "release_id": f"{release_prefix}_awsim",
                                "lane": "exec",
                                "result": "pass",
                                "runtime_evidence_path": str(
                                    reports_root / f"{release_prefix}_awsim_runtime_available_evidence.json"
                                ),
                                "runtime_evidence_exists": True,
                            },
                            {
                                "runtime": "carla",
                                "release_id": f"{release_prefix}_carla",
                                "lane": "exec",
                                "result": "pass",
                                "runtime_evidence_path": str(
                                    reports_root / f"{release_prefix}_carla_runtime_available_evidence.json"
                                ),
                                "runtime_evidence_exists": True,
                            },
                        ],
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            out_text = tmp_path / "summary.txt"
            out_json = tmp_path / "summary.json"
            out_db = tmp_path / "summary.sqlite"
            notification_out = tmp_path / "notify.json"
            step_summary = tmp_path / "step_summary.md"

            proc = run_script(
                PROTOTYPE_DIR / "run_ci_summary.py",
                "--artifacts-root",
                str(artifacts_root),
                "--release-prefix",
                release_prefix,
                "--summary-files-subpath",
                "reports",
                "--out-text",
                str(out_text),
                "--out-json",
                str(out_json),
                "--out-db",
                str(out_db),
                "--summary-title",
                "Runtime Threshold Drift Gate",
                "--workflow-name",
                "Runtime Available",
                "--notification-out-json",
                str(notification_out),
                "--notify-runtime-lane-execution-hold-min-exec-rows",
                "1",
                "--fail-on-runtime-threshold-drift-hold",
                "--step-summary-file",
                str(step_summary),
                expected_rc=1,
            )
            self.assertIn(
                "[error] run_ci_summary.py: runtime threshold drift hold policy failed: severity=HOLD",
                proc.stderr,
            )
            self.assertNotIn("Traceback", proc.stderr)
            self.assertTrue(out_json.exists())
            self.assertTrue(notification_out.exists())

            notification_payload = read_json_file(
                self,
                file_path=notification_out,
            )
            self.assertEqual(notification_payload.get("runtime_threshold_drift_severity"), "HOLD")
            self.assertTrue(bool(notification_payload.get("threshold_drift_hold_policy_failure_detected")))
            self.assertEqual(int(notification_payload.get("threshold_drift_hold_policy_failure_count", 0)), 1)
            notification_failures = notification_payload.get("threshold_drift_hold_policy_failures")
            self.assertIsInstance(notification_failures, list)
            assert isinstance(notification_failures, list)
            self.assertEqual(len(notification_failures), 1)
            self.assertTrue(any("reason_keys=" in str(item) for item in notification_failures))
            notification_reason_keys = notification_payload.get("threshold_drift_hold_policy_failure_reason_keys")
            self.assertIsInstance(notification_reason_keys, list)
            assert isinstance(notification_reason_keys, list)
            self.assertTrue(any(str(item).startswith("runtime_") for item in notification_reason_keys))
            notification_reason_key_counts = notification_payload.get("threshold_drift_hold_policy_failure_reason_key_counts")
            self.assertIsInstance(notification_reason_key_counts, dict)
            assert isinstance(notification_reason_key_counts, dict)
            self.assertTrue(any(str(key).startswith("runtime_") for key in notification_reason_key_counts.keys()))
            self.assertTrue(all(int(value) > 0 for value in notification_reason_key_counts.values()))
            notification_scope_counts = notification_payload.get("threshold_drift_hold_policy_failure_scope_counts")
            self.assertEqual(notification_scope_counts, {"runtime": 1})
            notification_scope_reason_key_counts = notification_payload.get(
                "threshold_drift_hold_policy_failure_scope_reason_key_counts"
            )
            self.assertEqual(
                notification_scope_reason_key_counts,
                {
                    "runtime": {
                        "runtime_lane_execution_exec_lane_hold_min_rows_mismatch": 1,
                    }
                },
            )
            self.assertIn(
                "threshold_drift_hold_policy_failure_scope_counts=runtime:1",
                str(notification_payload.get("message_text", "")),
            )
            self.assertIn(
                "threshold_drift_hold_policy_failure_scope_reason_key_counts="
                "runtime|runtime_lane_execution_exec_lane_hold_min_rows_mismatch:1",
                str(notification_payload.get("message_text", "")),
            )
            self.assertIn(
                "threshold_drift_hold_policy_failure_reason_key_counts=",
                str(notification_payload.get("message_text", "")),
            )
            summary_payload = read_json_file(
                self,
                file_path=out_json,
            )
            self.assertTrue(bool(summary_payload.get("threshold_drift_hold_policy_failure_detected")))
            self.assertEqual(int(summary_payload.get("threshold_drift_hold_policy_failure_count", 0)), 1)
            self.assertEqual(
                summary_payload.get("threshold_drift_hold_policy_failure_reason_key_counts"),
                notification_reason_key_counts,
            )
            self.assertEqual(
                summary_payload.get("threshold_drift_hold_policy_failure_scope_counts"),
                notification_scope_counts,
            )
            self.assertEqual(
                summary_payload.get("threshold_drift_hold_policy_failure_scope_reason_key_counts"),
                notification_scope_reason_key_counts,
            )
            self.assertIn(
                "threshold_drift_hold_policy_failure_scope_counts=runtime:1",
                out_text.read_text(encoding="utf-8"),
            )
            self.assertIn(
                "threshold_drift_hold_policy_failure_scope_reason_key_counts="
                "runtime|runtime_lane_execution_exec_lane_hold_min_rows_mismatch:1",
                out_text.read_text(encoding="utf-8"),
            )
            self.assertIn(
                "threshold_drift_hold_policy_failure_reason_key_counts=",
                out_text.read_text(encoding="utf-8"),
            )
            assert_step_summary_ci_error(
                self,
                step_summary_path=step_summary,
                source="run_ci_summary.py",
                phase=SUMMARY_PHASE_BUILD_NOTIFICATION_PAYLOAD,
                message_substring="runtime threshold drift hold policy failed: severity=HOLD",
            )
            step_summary_text = step_summary.read_text(encoding="utf-8")
            self.assertIn("reason_key_counts=", step_summary_text)
            self.assertIn("runtime_lane_execution_exec_lane_hold_min_rows_mismatch", step_summary_text)

