    def test_fail_on_rn2_threshold_hold_reports_policy_error(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            release_prefix = "REL_TEST_RN2_THRESHOLD_GATE_HOLD_001"
            artifacts_root = tmp_path / "artifacts"
            reports_root = artifacts_root / "reports"
            batch_root = artifacts_root / "batch_rn2"
            reports_root.mkdir(parents=True, exist_ok=True)
            batch_root.mkdir(parents=True, exist_ok=True)

            (reports_root / f"{release_prefix}_sds_v0.1.0.summary.json").write_text(
                json.dumps(
                    {
                        "release_id": f"{release_prefix}_sds_v0_1_0",
                        "sds_version": "sds_v0.1.0",
                        "final_result": "PASS",
                        "generated_at": "2026-01-01T00:00:00+00:00",
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            for batch_idx in (1, 2):
                batch_id = f"BATCH_RN2_{batch_idx:03d}"
                batch_dir = batch_root / batch_id.lower()
                batch_dir.mkdir(parents=True, exist_ok=True)
                log_replay_manifest = batch_dir / "log_replay_manifest.json"
                log_replay_summary = batch_dir / "log_replay_summary.json"
                log_replay_summary.write_text(
                    json.dumps({"status": "fail"}) + "\n",
                    encoding="utf-8",
                )
                log_replay_manifest.write_text(
                    json.dumps(
                        {
                            "status": "fail",
                            "summary_path": str(log_replay_summary.name),
                            "log_id": f"LOG_{batch_idx:03d}",
                        }
                    )
                    + "\n",
                    encoding="utf-8",
                )
                (batch_dir / "pipeline_result.json").write_text(
                    json.dumps(
                        {
                            "release_id": f"{release_prefix}_sds_v0_1_0",
                            "batch_id": batch_id,
                            "overall_result": "PASS",
                            "strict_gate": True,
                            "trend_gate": {"result": "PASS"},
                            "reports": [{"sds_version": "sds_v0.1.0"}],
                            "phase2_hooks": {
                                "enabled": True,
                                "log_replay_manifest_path": str(log_replay_manifest.name),
                            },
                        }
                    )
                    + "\n",
                    encoding="utf-8",
                )

            out_text = tmp_path / "summary.txt"
            out_json = tmp_path / "summary.json"
            out_db = tmp_path / "summary.sqlite"
            notification_out = tmp_path / "notify.json"
            step_summary = tmp_path / "step_summary.md"

            proc = run_script(
                PROTOTYPE_DIR / "run_ci_summary.py",
                "--artifacts-root",
                str(artifacts_root),
                "--release-prefix",
                release_prefix,
                "--summary-files-subpath",
                "reports",
                "--pipeline-manifests-subpath",
                "batch_rn2",
                "--out-text",
                str(out_text),
                "--out-json",
                str(out_json),
                "--out-db",
                str(out_db),
                "--summary-title",
                "RN2 Threshold Hold Gate",
                "--workflow-name",
                "Runtime Available",
                "--notification-out-json",
                str(notification_out),
                "--notify-phase2-log-replay-fail-warn-max",
                "1",
                "--notify-phase2-log-replay-fail-hold-max",
                "1",
                "--notify-runtime-native-smoke-fail-warn-max",
                "1",
                "--notify-runtime-native-smoke-fail-hold-max",
                "1",
                "--fail-on-phase2-log-replay-threshold-hold",
                "--fail-on-runtime-native-smoke-threshold-hold",
                "--step-summary-file",
                str(step_summary),
                expected_rc=1,
            )
            self.assertIn(
                "[error] run_ci_summary.py: phase2 log replay threshold drift hold policy failed: severity=HOLD",
                proc.stderr,
            )
            self.assertIn(
                "runtime native smoke threshold drift hold policy failed: severity=HOLD",
                proc.stderr,
            )
            self.assertLess(
                proc.stderr.index("phase2 log replay threshold drift hold policy failed"),
                proc.stderr.index("runtime native smoke threshold drift hold policy failed"),
            )
            self.assertNotIn("Traceback", proc.stderr)
            self.assertTrue(out_json.exists())
            self.assertTrue(notification_out.exists())

            notification_payload = read_json_file(
                self,
                file_path=notification_out,
            )
            self.assertTrue(bool(notification_payload.get("threshold_drift_hold_policy_failure_detected")))
            self.assertEqual(int(notification_payload.get("threshold_drift_hold_policy_failure_count", 0)), 2)
            self.assertEqual(
                notification_payload.get("threshold_drift_hold_policy_failure_scope_counts"),
                {
                    "phase2_log_replay": 1,
                    "runtime_native_smoke": 1,
                },
            )
            self.assertEqual(
                notification_payload.get("threshold_drift_hold_policy_failure_scope_reason_key_counts"),
                {
                    "phase2_log_replay": {
                        "phase2_log_replay_fail_count_above_hold_max": 1,
                    },
                    "runtime_native_smoke": {
                        "runtime_native_smoke_fail_count_above_hold_max": 1,
                    },
                },
            )
            self.assertEqual(
                notification_payload.get("threshold_drift_hold_policy_failure_reason_key_counts"),
                {
                    "phase2_log_replay_fail_count_above_hold_max": 1,
                    "runtime_native_smoke_fail_count_above_hold_max": 1,
                },
            )
            self.assertIn(
                "threshold_drift_hold_policy_failure_scope_counts=phase2_log_replay:1,runtime_native_smoke:1",
                str(notification_payload.get("message_text", "")),
            )
            self.assertIn(
                "phase2_log_replay|phase2_log_replay_fail_count_above_hold_max:1",
                str(notification_payload.get("message_text", "")),
            )
            self.assertIn(
                "runtime_native_smoke|runtime_native_smoke_fail_count_above_hold_max:1",
                str(notification_payload.get("message_text", "")),
            )

            summary_payload = read_json_file(
                self,
                file_path=out_json,
            )
            self.assertTrue(bool(summary_payload.get("threshold_drift_hold_policy_failure_detected")))
            self.assertEqual(int(summary_payload.get("threshold_drift_hold_policy_failure_count", 0)), 2)
            self.assertEqual(
                summary_payload.get("threshold_drift_hold_policy_failure_scope_counts"),
                notification_payload.get("threshold_drift_hold_policy_failure_scope_counts"),
            )
            self.assertEqual(
                summary_payload.get("threshold_drift_hold_policy_failure_scope_reason_key_counts"),
                notification_payload.get("threshold_drift_hold_policy_failure_scope_reason_key_counts"),
            )
            self.assertEqual(
                summary_payload.get("threshold_drift_hold_policy_failure_reason_key_counts"),
                notification_payload.get("threshold_drift_hold_policy_failure_reason_key_counts"),
            )
            self.assertIn(
                "threshold_drift_hold_policy_failure_scope_counts=phase2_log_replay:1,runtime_native_smoke:1",
                out_text.read_text(encoding="utf-8"),
            )
            assert_step_summary_ci_error(
                self,
                step_summary_path=step_summary,
                source="run_ci_summary.py",
                phase=SUMMARY_PHASE_BUILD_NOTIFICATION_PAYLOAD,
                message_substring="phase2 log replay threshold drift hold policy failed: severity=HOLD",
            )
            self.assertIn(
                "runtime native smoke threshold drift hold policy failed: severity=HOLD",
                step_summary.read_text(encoding="utf-8"),
            )

