            self.assertTrue(bool(summary_payload.get("threshold_drift_hold_policy_failure_detected")))
            self.assertEqual(int(summary_payload.get("threshold_drift_hold_policy_failure_count", 0)), 4)
            failure_items = summary_payload.get("threshold_drift_hold_policy_failures")
