            assert isinstance(summary_reason_keys, list)
            self.assertTrue(any(str(item).startswith("runtime_") for item in summary_reason_keys))
            self.assertTrue(any(str(item).startswith("phase3_core_sim_") for item in summary_reason_keys))
            self.assertTrue(any(str(item).startswith("phase3_lane_risk_") for item in summary_reason_keys))
