class CompareRuntimeEvidenceScriptTests(unittest.TestCase):
    def test_compare_runtime_evidence_emits_diff_artifacts(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
