    def test_ingest_command_failure_includes_exit_code_and_detail(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            artifacts_root = tmp_path / "artifacts"
            artifacts_root.mkdir(parents=True, exist_ok=True)
            summary_path = artifacts_root / "REL_TEST_ARTIFACT_001_sds_v0.1.0.summary.json"
            summary_path.write_text(
                json.dumps(
                    {
                        "release_id": "REL_TEST_ARTIFACT_001",
                        "sds_version": "sds_v0.1.0",
                        "final_result": "PASS",
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            fake_python = tmp_path / "fake_python.sh"
            fake_python.write_text(
                "\n".join(
                    [
                        "#!/usr/bin/env bash",
                        "echo 'fake python boom' 1>&2",
                        "exit 7",
                    ]
                )
                + "\n",
                encoding="utf-8",
            )
            os.chmod(fake_python, 0o755)

            proc = run_script(
                PROTOTYPE_DIR / "build_release_summary_artifact.py",
                "--artifacts-root",
                str(artifacts_root),
                "--release-prefix",
                "REL_TEST_ARTIFACT_001",
                "--out-text",
                str(tmp_path / "summary.txt"),
                "--out-json",
                str(tmp_path / "summary.json"),
                "--out-db",
                str(tmp_path / "summary.sqlite"),
                "--python-bin",
                str(fake_python),
                expected_rc=1,
            )

            combined = f"{proc.stdout}\n{proc.stderr}"
            self.assertIn("command failed with exit code 7", combined)
            self.assertIn(str(fake_python), combined)
            self.assertIn("fake python boom", combined)
            self.assertNotIn("fake python boom", proc.stdout)
            self.assertIn("fake python boom", proc.stderr)
            self.assertIn("[error] build_release_summary_artifact.py:", proc.stderr)
            self.assertNotIn("Traceback", proc.stderr)

