            summary_b = reports_root / "REL_ROOT_CAUSE_001_sds_v0.2.0.summary.json"
            summary_a.write_text(
                json.dumps(
                    {
                        "release_id": "REL_ROOT_CAUSE_001_sds_v0_1_0",
                        "sds_version": "sds_v0.1.0",
                        "final_result": "HOLD",
                        "generated_at": "2026-01-01T00:00:00+00:00",
                        "hold_reason_codes": [
                            "gate_collision_rate_high",
                            "requirement_hold",
                        ],
                        "hold_reasons": [
                            "gate_collision_rate_high",
                            "requirement_req_a_hold",
                        ],
                        "gate_reasons": ["collision_rate_high"],
                        "requirement_hold_records": [
                            {"requirement_id": "REQ_A", "status": "HOLD"},
                            {"requirement_id": "REQ_B", "status": "PASS"},
                        ],
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            summary_b.write_text(
                json.dumps(
                    {
                        "release_id": "REL_ROOT_CAUSE_001_sds_v0_2_0",
                        "sds_version": "sds_v0.2.0",
                        "final_result": "HOLD",
                        "generated_at": "2026-01-01T00:01:00+00:00",
                        "hold_reason_codes": [
                            "gate_collision_rate_high",
                            "sim_timeout",
                        ],
                        "hold_reasons": [
                            "gate_collision_rate_high",
                            "sim_timeout",
                        ],
                        "gate_reasons": ["collision_rate_high"],
                        "requirement_hold_records": [
                            {"requirement_id": "REQ_A", "status": "HOLD"},
                        ],
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            out_text = tmp_path / "summary.txt"
            out_json = tmp_path / "summary.json"
            run_script(
                PROTOTYPE_DIR / "build_release_summary_artifact.py",
                "--artifacts-root",
                str(reports_root),
                "--release-prefix",
                "REL_ROOT_CAUSE_001",
                "--out-text",
                str(out_text),
                "--out-json",
                str(out_json),
                "--out-db",
                str(tmp_path / "summary.sqlite"),
            )

            payload = read_json_file(
                self,
                file_path=out_json,
            )
            root_cause = payload.get("root_cause_summary", {})
            self.assertIsInstance(root_cause, dict)

            def _rows_to_counts(rows: object) -> dict[str, int]:
                result: dict[str, int] = {}
                if not isinstance(rows, list):
                    return result
                for row in rows:
                    if not isinstance(row, dict):
                        continue
                    value = str(row.get("value", "")).strip()
                    if not value:
                        continue
                    result[value] = int(row.get("count", 0))
                return result

            code_counts = _rows_to_counts(root_cause.get("hold_reason_codes"))
            raw_counts = _rows_to_counts(root_cause.get("hold_reasons_raw"))
            gate_counts = _rows_to_counts(root_cause.get("gate_reasons"))
            req_counts = _rows_to_counts(root_cause.get("requirement_hold_ids"))
            self.assertEqual(code_counts.get("gate_collision_rate_high"), 2)
            self.assertEqual(code_counts.get("requirement_hold"), 1)
            self.assertEqual(code_counts.get("sim_timeout"), 1)
            self.assertEqual(raw_counts.get("gate_collision_rate_high"), 2)
            self.assertEqual(gate_counts.get("collision_rate_high"), 2)
            self.assertEqual(req_counts.get("REQ_A"), 2)
            self.assertNotIn("REQ_B", req_counts)

            assert_text_file_contains(
                self,
                file_path=out_text,
                expected_substrings=[
                    "## root-cause-summary",
                    "### requirement_hold_ids",
                    "| REQ_A | 2 |",
                ],
            )

