    def test_release_diff_missing_assessment_rows_is_reported_as_info(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            artifacts_root = tmp_path / "artifacts"
            reports_root = artifacts_root / "reports"
            reports_root.mkdir(parents=True, exist_ok=True)

            release_prefix = "REL_TEST_RELEASE_DIFF_MISSING_001"
            for runtime in ("awsim", "carla"):
                for sds_version in ("sds_v0.1.0", "sds_v0.2.0"):
                    summary_path = reports_root / f"{release_prefix}_{runtime}_{sds_version}.summary.json"
                    summary_path.write_text(
                        json.dumps(
                            {
                                "release_id": f"{release_prefix}_{runtime}_{sds_version.replace('.', '_')}",
                                "sds_version": sds_version,
                                "final_result": "PASS",
                                "generated_at": "2026-01-01T00:00:00+00:00",
                            }
                        )
                        + "\n",
                        encoding="utf-8",
                    )

            out_text = tmp_path / "summary.txt"
            out_json = tmp_path / "summary.json"
            run_script(
                PROTOTYPE_DIR / "build_release_summary_artifact.py",
                "--artifacts-root",
                str(artifacts_root),
                "--release-prefix",
                release_prefix,
                "--out-text",
                str(out_text),
                "--out-json",
                str(out_json),
                "--out-db",
                str(tmp_path / "summary.sqlite"),
            )

            summary_text = out_text.read_text(encoding="utf-8")
            self.assertIn("## release-diff", summary_text)
            self.assertIn(
                "[info] skipped: no release assessment rows for release-diff "
                f"(release_prefix={release_prefix}, version_a=sds_v0.1.0, version_b=sds_v0.2.0)",
                summary_text,
            )
            self.assertNotIn(
                "[error] no release assessment found for prefix=",
                summary_text,
            )

