            pipeline_manifest_path = batch_root / "pipeline_result.json"
            pipeline_manifest_path.write_text(
                json.dumps(
                    {
                        "release_id": "REL_TEST_PHASE3_CORE_SIM_MATRIX_001_sds_v0_1_0",
                        "batch_id": "BATCH_MATRIX",
                        "overall_result": "PASS",
                        "strict_gate": True,
                        "trend_gate": {"result": "PASS"},
                        "phase3_hooks": {
                            "enabled": True,
                            "phase3_core_sim_matrix": {
                                "enabled": True,
                                "phase3_core_sim_matrix_schema_version": "core_sim_matrix_sweep_report_v0",
                                "case_count": 4,
                                "success_case_count": 3,
                                "failed_case_count": 1,
                                "all_cases_success": False,
                                "collision_case_count": 1,
                                "timeout_case_count": 0,
                                "min_ttc_same_lane_sec_min": 1.35,
                                "lowest_ttc_same_lane_run_id": "RUN_MAT_0004",
                                "min_ttc_any_lane_sec_min": 1.2,
                                "lowest_ttc_any_lane_run_id": "RUN_MAT_0002",
                                "status_counts": {"success": 3, "failed": 1},
                                "returncode_counts": {"0": 3, "1": 1},
                            },
                        },
                        "reports": [{"sds_version": "sds_v0.1.0"}],
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            out_text = tmp_path / "summary.txt"
            out_json = tmp_path / "summary.json"
            run_script(
                PROTOTYPE_DIR / "build_release_summary_artifact.py",
                "--artifacts-root",
                str(artifacts_root),
                "--release-prefix",
                "REL_TEST_PHASE3_CORE_SIM_MATRIX_001",
                "--out-text",
                str(out_text),
                "--out-json",
                str(out_json),
                "--out-db",
                str(tmp_path / "summary.sqlite"),
            )

            payload = read_json_file(self, file_path=out_json)
            matrix_summary = payload.get("phase3_core_sim_matrix_summary", {})
            self.assertIsInstance(matrix_summary, dict)
            self.assertEqual(int(matrix_summary.get("evaluated_manifest_count", 0) or 0), 1)
            self.assertEqual(int(matrix_summary.get("pipeline_manifest_count", 0) or 0), 1)
            self.assertEqual(int(matrix_summary.get("enabled_manifest_count", 0) or 0), 1)
            self.assertEqual(int(matrix_summary.get("case_count_total", 0) or 0), 4)
            self.assertEqual(int(matrix_summary.get("success_case_count_total", 0) or 0), 3)
            self.assertEqual(int(matrix_summary.get("failed_case_count_total", 0) or 0), 1)
            self.assertEqual(int(matrix_summary.get("collision_case_count_total", 0) or 0), 1)
            self.assertEqual(int(matrix_summary.get("timeout_case_count_total", 0) or 0), 0)
            self.assertEqual(matrix_summary.get("status_counts"), {"failed": 1, "success": 3})
            self.assertEqual(matrix_summary.get("returncode_counts"), {"0": 3, "1": 1})
