            self.assertAlmostEqual(float(matrix_summary.get("min_ttc_any_lane_sec_min", 0.0) or 0.0), 1.2, places=6)
            self.assertEqual(str(matrix_summary.get("lowest_ttc_same_lane_batch_id", "")), "BATCH_MATRIX")
            self.assertEqual(str(matrix_summary.get("lowest_ttc_same_lane_run_id", "")), "RUN_MAT_0004")
            self.assertEqual(str(matrix_summary.get("lowest_ttc_any_lane_batch_id", "")), "BATCH_MATRIX")
            self.assertEqual(str(matrix_summary.get("lowest_ttc_any_lane_run_id", "")), "RUN_MAT_0002")
            assert_text_file_contains(
                self,
                file_path=out_text,
                expected_substrings=[
                    "phase3_core_sim_matrix=evaluated:1,enabled_manifests:1,cases_total:4,success_cases_total:3,failed_cases_total:1",
                    "statuses:failed:1,success:3,returncodes:0:3,1:1",
                    "min_ttc_same_lane:1.350(BATCH_MATRIX|RUN_MAT_0004),min_ttc_any_lane:1.200(BATCH_MATRIX|RUN_MAT_0002)",
                ],
            )

