class BuildNotificationPayloadTests(unittest.TestCase):
    def test_status_and_reason_code_truncation(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            summary_path = tmp_path / "summary.json"
            out_path = tmp_path / "notification.json"
            summary_path.write_text(
                json.dumps(
                    {
                        "release_prefix": "REL_TEST_001",
                        "summary_count": 2,
                        "pipeline_manifest_count": 1,
                        "sds_versions": ["sds_v0.1.0", "sds_v0.2.0"],
                        "final_result_counts": {"PASS": 1, "HOLD": 1},
                        "pipeline_overall_counts": {"PASS": 0, "HOLD": 1},
                        "pipeline_trend_counts": {"PASS": 1, "HOLD": 0},
                        "timing_ms": {"scan_summary_files": 11, "scan_pipeline_manifests": 5, "total": 63},
                        "reason_code_diff": {
                            "codes_only_in_a": ["A1", "A2", "A3"],
                            "codes_only_in_b": ["B1", "B2", "B3"],
                            "codes_common": ["C1", "C2", "C3"],
                        },
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            run_script(
                PROTOTYPE_DIR / "build_release_notification_payload.py",
                "--summary-json",
                str(summary_path),
                "--out-json",
                str(out_path),
                "--workflow-name",
                "E2E PR Quick Pipeline",
                "--run-url",
                "https://example.invalid/actions/1",
                "--max-codes",
                "2",
            )
            payload = read_json_file(
                self,
                file_path=out_path,
            )
            self.assertEqual(payload["status"], "HOLD")
            self.assertEqual(payload["pipeline_manifest_count"], 1)
            self.assertEqual(payload["workflow_name"], "E2E PR Quick Pipeline")
            self.assertIn("... (+1 more)", payload["message_text"])
            self.assertIn("pipeline_manifest_count=1", payload["message_text"])
            self.assertIn("timing_total_ms=63", payload["message_text"])
            self.assertIn("pipeline_trend=HOLD:0,PASS:1", payload["message_text"])
            self.assertEqual(payload.get("timing_ms", {}).get("total"), 63)
            self.assertEqual(payload.get("timing_warning_severity"), "")
            self.assertEqual(payload.get("timing_warning_reasons"), [])
            self.assertIn("Open CI run", json.dumps(payload["slack"]))

    def test_warning_forces_warn_status(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            summary_path = tmp_path / "summary.json"
            out_path = tmp_path / "notification.json"
            summary_path.write_text(
                json.dumps(
                    {
                        "release_prefix": "REL_WARN_001",
                        "summary_count": 0,
                        "final_result_counts": {"PASS": 3},
                        "warning": "no summary files found",
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            run_script(
                PROTOTYPE_DIR / "build_release_notification_payload.py",
                "--summary-json",
                str(summary_path),
                "--out-json",
                str(out_path),
            )
            payload = read_json_file(
                self,
                file_path=out_path,
            )
            self.assertEqual(payload["status"], "WARN")
            self.assertIn("warning=no summary files found", payload["message_text"])

    def test_runtime_evidence_failures_promote_pass_to_warn(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            summary_path = tmp_path / "summary.json"
            out_path = tmp_path / "notification.json"
            summary_path.write_text(
                json.dumps(
                    {
                        "release_prefix": "REL_RUNTIME_NOTIFY_WARN_001",
                        "summary_count": 2,
                        "final_result_counts": {"PASS": 2},
                        "pipeline_overall_counts": {"PASS": 1},
                        "pipeline_trend_counts": {"PASS": 1},
                        "runtime_evidence_summary": {
                            "artifact_count": 1,
                            "record_count": 2,
                            "validated_count": 1,
                            "failed_count": 1,
                            "runtime_counts": {"carla": 1},
                            "status_counts": {"failed": 1, "validated": 1},
                            "availability_true_count": 1,
                            "availability_false_count": 0,
                            "availability_unknown_count": 1,
                            "probe_checked_count": 1,
                            "probe_executed_count": 1,
                            "runtime_bin_missing_count": 0,
                            "failed_records": [
                                {
                                    "profile_id": "matrix_profile_b",
                                    "release_id": "REL_RUNTIME_NOTIFY_WARN_001_matrix_profile_b",
                                    "error": "runtime binary unavailable",
                                }
                            ],
                        },
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            run_script(
                PROTOTYPE_DIR / "build_release_notification_payload.py",
                "--summary-json",
                str(summary_path),
                "--out-json",
                str(out_path),
            )
            payload = read_json_file(
                self,
                file_path=out_path,
            )
            self.assertEqual(payload["status"], "WARN")
            self.assertIn("runtime_evidence_warning=runtime_evidence_failed=1/2", payload["message_text"])
            self.assertIn(
                "runtime_evidence_warning_reasons=runtime_evidence_failed_records",
                payload["message_text"],
            )
            self.assertIn("runtime_evidence_failed_records=", payload["message_text"])
            self.assertEqual(payload.get("runtime_evidence_warning_reasons"), ["runtime_evidence_failed_records"])
            self.assertIn("*runtime evidence*", json.dumps(payload.get("slack", {})))

