    def test_timing_regression_promotes_pass_to_warn(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            summary_path = tmp_path / "summary.json"
            out_path = tmp_path / "notification.json"
            summary_path.write_text(
                json.dumps(
                    {
                        "release_prefix": "REL_TIMING_REGRESSION_WARN_001",
                        "summary_count": 2,
                        "final_result_counts": {"PASS": 2},
                        "pipeline_overall_counts": {"PASS": 1},
                        "pipeline_trend_counts": {"PASS": 1},
                        "timing_ms": {"total": 1500},
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            run_script(
                PROTOTYPE_DIR / "build_release_notification_payload.py",
                "--summary-json",
                str(summary_path),
                "--out-json",
                str(out_path),
                "--timing-regression-baseline-ms",
                "1000",
                "--timing-regression-warn-ratio",
                "0.3",
            )
            payload = read_json_file(
                self,
                file_path=out_path,
            )
            self.assertEqual(payload["status"], "WARN")
            self.assertEqual(payload.get("timing_regression_baseline_ms"), 1000)
            self.assertEqual(payload.get("timing_regression_warn_ratio"), 0.3)
            regression = payload.get("timing_regression", {})
            self.assertEqual(regression.get("current_ms"), 1500)
            self.assertEqual(regression.get("baseline_ms"), 1000)
            self.assertEqual(regression.get("delta_ms"), 500)
            self.assertAlmostEqual(float(regression.get("delta_ratio", 0.0)), 0.5, places=6)
            self.assertEqual(regression.get("warn_ratio"), 0.3)
            self.assertAlmostEqual(float(regression.get("ratio_multiple", 0.0)), 5.0 / 3.0, places=6)
            self.assertTrue(regression.get("exceeded"))
            self.assertIn(
                "timing_regression=0.500 exceeded ratio=0.300 (current=1500, baseline=1000)",
                payload.get("timing_warning", ""),
            )
            self.assertEqual(payload.get("timing_warning_severity"), "WARN")
            self.assertEqual(payload.get("timing_warning_reasons"), ["regression_ratio"])
            self.assertIn("timing_regression=", payload.get("message_text", ""))
            slack_text = json.dumps(payload.get("slack", {}))
            self.assertIn("timing_regression: baseline_source=explicit", slack_text)
            self.assertIn("baseline_ms=1000", slack_text)

