    def test_timing_regression_uses_history_median_baseline(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            history_dir = tmp_path / "history"
            history_dir.mkdir(parents=True, exist_ok=True)

            history_items = [
                {"release_prefix": "REL_PR_199_2", "total_ms": 1000},
                {"release_prefix": "REL_PR_198_9", "total_ms": 1200},
                {"release_prefix": "REL_PR_197_4", "total_ms": 800},
                {"release_prefix": "REL_CI_300_1", "total_ms": 6000},
                {"release_prefix": "REL_PR_201_1", "total_ms": 1600},
            ]
            base_ts = 1_700_000_000
            for idx, item in enumerate(history_items, start=1):
                history_path = history_dir / f"hist_{idx:02d}_release_summary.json"
                history_path.write_text(
                    json.dumps(
                        {
                            "release_prefix": item["release_prefix"],
                            "timing_ms": {"total": item["total_ms"]},
                        }
                    )
                    + "\n",
                    encoding="utf-8",
                )
                ts = float(base_ts + idx)
                os.utime(history_path, (ts, ts))

            summary_path = tmp_path / "current_release_summary.json"
            out_path = tmp_path / "notification.json"
            summary_path.write_text(
                json.dumps(
                    {
                        "release_prefix": "REL_PR_200_3",
                        "summary_count": 2,
                        "final_result_counts": {"PASS": 2},
                        "pipeline_overall_counts": {"PASS": 1},
                        "pipeline_trend_counts": {"PASS": 1},
                        "timing_ms": {"total": 1800},
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            run_script(
                PROTOTYPE_DIR / "build_release_notification_payload.py",
                "--summary-json",
                str(summary_path),
                "--out-json",
                str(out_path),
                "--timing-regression-warn-ratio",
                "0.4",
                "--timing-regression-history-window",
                "3",
                "--timing-regression-history-dir",
                str(history_dir),
            )
            payload = read_json_file(
                self,
                file_path=out_path,
            )
            self.assertEqual(payload["status"], "WARN")
            self.assertEqual(payload.get("timing_regression_baseline_source"), "history_median")
            self.assertEqual(payload.get("timing_regression_baseline_ms"), 1000)
            self.assertEqual(payload.get("timing_regression_history_window"), 3)
            self.assertEqual(
                payload.get("timing_regression_history_filter"),
                {
                    "release_prefix": "REL_PR_200_3",
                    "release_lineage": "REL_PR",
                    "release_sequence": [200, 3],
                    "outlier_method": "none",
                    "trim_ratio": 0.0,
                    "raw_count": 3,
                    "used_count": 3,
                    "dropped_count": 0,
                },
            )
            self.assertEqual(payload.get("timing_regression_history_samples_raw_ms"), [1000, 1200, 800])
            self.assertEqual(payload.get("timing_regression_history_samples_ms"), [1000, 1200, 800])
            regression = payload.get("timing_regression", {})
            self.assertEqual(regression.get("baseline_ms"), 1000)
            self.assertEqual(regression.get("current_ms"), 1800)
            self.assertTrue(regression.get("exceeded"))
