class SendNotificationTests(unittest.TestCase):
    def test_notify_policy_suppresses_send(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            payload_path = tmp_path / "payload.json"
            payload_path.write_text(
                json.dumps({"status": "PASS", "slack": {"text": "ok"}}) + "\n",
                encoding="utf-8",
            )

            proc = run_script(
                PROTOTYPE_DIR / "send_release_notification.py",
                "--payload-json",
                str(payload_path),
                "--webhook-url",
                "https://example.invalid/webhook",
                "--notify-on",
                "hold",
            )
            self.assertIn("[skip] notification suppressed", proc.stdout)

    def test_notify_policy_warn_sends_only_warn_status(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            warn_payload = tmp_path / "warn_payload.json"
            pass_payload = tmp_path / "pass_payload.json"
            webhook_url = "https://example.invalid/webhook"
            warn_payload.write_text(
                json.dumps({"status": "WARN", "message_text": "warn msg"}) + "\n",
                encoding="utf-8",
            )
            pass_payload.write_text(
                json.dumps({"status": "PASS", "message_text": "pass msg"}) + "\n",
                encoding="utf-8",
            )

            warn_proc = run_script(
                PROTOTYPE_DIR / "send_release_notification.py",
                "--payload-json",
                str(warn_payload),
                "--webhook-url",
                webhook_url,
                "--notify-on",
                "warn",
                "--dry-run",
            )
            self.assertIn("[dry-run]", warn_proc.stdout)
            self.assertNotIn("[skip] notification suppressed", warn_proc.stdout)

            pass_proc = run_script(
                PROTOTYPE_DIR / "send_release_notification.py",
                "--payload-json",
                str(pass_payload),
                "--webhook-url",
                webhook_url,
                "--notify-on",
                "warn",
            )
            self.assertIn("[skip] notification suppressed", pass_proc.stdout)

