    def test_dry_run_slack_and_raw_formats(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            payload_path = tmp_path / "payload.json"
            webhook_url = "https://example.invalid/webhook"
            payload_path.write_text(
                json.dumps(
                    {
                        "schema_version": "release_notification_v1",
                        "status": "HOLD",
                        "message_text": "fallback text",
                        "slack": {"text": "slack text", "blocks": [{"type": "section"}]},
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            slack_proc = run_script(
                PROTOTYPE_DIR / "send_release_notification.py",
                "--payload-json",
                str(payload_path),
                "--webhook-url",
                webhook_url,
                "--notify-on",
                "always",
                "--format",
                "slack",
                "--dry-run",
            )
            self.assertIn("[dry-run]", slack_proc.stdout)
            self.assertNotIn(webhook_url, slack_proc.stdout)
            self.assertIn("url=***", slack_proc.stdout)
            self.assertIn("\"text\": \"slack text\"", slack_proc.stdout)

            raw_proc = run_script(
                PROTOTYPE_DIR / "send_release_notification.py",
                "--payload-json",
                str(payload_path),
                "--webhook-url",
                webhook_url,
                "--notify-on",
                "always",
                "--format",
                "raw",
                "--dry-run",
            )
            self.assertNotIn(webhook_url, raw_proc.stdout)
            self.assertIn("url=***", raw_proc.stdout)
            self.assertIn("\"schema_version\": \"release_notification_v1\"", raw_proc.stdout)

