    def test_parse_retry_after_seconds_http_date_with_fixed_now(self) -> None:
        now_utc = datetime(2026, 2, 26, 0, 0, 0, tzinfo=timezone.utc)
        self.assertEqual(
            _parse_retry_after_seconds("Thu, 26 Feb 2026 00:00:10 GMT", now_utc=now_utc),
            10.0,
        )
        self.assertEqual(
            _parse_retry_after_seconds("Wed, 25 Feb 2026 23:59:50 GMT", now_utc=now_utc),
            0.0,
        )

    def test_http_429_retries_and_succeeds(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            payload_path = tmp_path / "payload.json"
            payload_path.write_text(
                json.dumps({"status": "HOLD", "message_text": "msg"}) + "\n",
                encoding="utf-8",
            )

            request_count = {"value": 0}
            statuses = [429, 200]

            class RetryHandler(BaseHTTPRequestHandler):
                def do_POST(self) -> None:  # noqa: N802
                    request_count["value"] += 1
                    length = int(self.headers.get("Content-Length", "0"))
                    if length > 0:
                        self.rfile.read(length)
                    status = statuses[min(request_count["value"] - 1, len(statuses) - 1)]
                    self.send_response(status)
                    if status == 429:
                        self.send_header("Retry-After", "0")
                    self.send_header("Content-Type", "application/json")
                    self.end_headers()
                    self.wfile.write(b'{"ok": true}')

                def log_message(self, _format: str, *_args: object) -> None:
                    return

            server = HTTPServer(("127.0.0.1", 0), RetryHandler)
            thread = threading.Thread(target=server.serve_forever, daemon=True)
            thread.start()
            try:
                webhook_url = f"http://127.0.0.1:{server.server_port}/webhook"
                started = time.monotonic()
                proc = run_script(
                    PROTOTYPE_DIR / "send_release_notification.py",
                    "--payload-json",
                    str(payload_path),
                    "--webhook-url",
                    webhook_url,
                    "--notify-on",
                    "always",
                    "--timeout-sec",
                    "1",
                    "--max-retries",
                    "1",
                    "--retry-backoff-sec",
                    "2",
                )
                elapsed = time.monotonic() - started
            finally:
                server.shutdown()
                server.server_close()
                thread.join(timeout=2)

            self.assertIn("[ok] sent status=200", proc.stdout)
            self.assertIn("[warn] retrying notification after http_error status=429", proc.stderr)
            self.assertIn("attempts=1/2", proc.stderr)
            self.assertIn("delay_sec=0.0", proc.stderr)
            self.assertNotIn("[warn] retrying notification after http_error status=429", proc.stdout)
            self.assertEqual(request_count["value"], 2)
            self.assertLess(elapsed, 1.8)

    def test_http_400_does_not_retry(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            tmp_path = Path(tmp)
            payload_path = tmp_path / "payload.json"
            payload_path.write_text(
                json.dumps({"status": "HOLD", "message_text": "msg"}) + "\n",
                encoding="utf-8",
            )

            request_count = {"value": 0}

            class ClientErrorHandler(BaseHTTPRequestHandler):
                def do_POST(self) -> None:  # noqa: N802
                    request_count["value"] += 1
                    length = int(self.headers.get("Content-Length", "0"))
                    if length > 0:
                        self.rfile.read(length)
                    self.send_response(400)
                    self.send_header("Content-Type", "application/json")
                    self.end_headers()
                    self.wfile.write(b'{"error": "bad request"}')

                def log_message(self, _format: str, *_args: object) -> None:
                    return

            server = HTTPServer(("127.0.0.1", 0), ClientErrorHandler)
            thread = threading.Thread(target=server.serve_forever, daemon=True)
            thread.start()
            try:
                webhook_url = f"http://127.0.0.1:{server.server_port}/webhook"
                proc = run_script(
                    PROTOTYPE_DIR / "send_release_notification.py",
                    "--payload-json",
                    str(payload_path),
                    "--webhook-url",
                    webhook_url,
                    "--notify-on",
                    "always",
                    "--timeout-sec",
                    "1",
                    "--max-retries",
                    "2",
                    "--retry-backoff-sec",
                    "0",
                    expected_rc=1,
                )
            finally:
                server.shutdown()
                server.server_close()
                thread.join(timeout=2)

            self.assertIn("http_error status=400", proc.stderr)
            self.assertIn("attempts=1/3", proc.stderr)
            self.assertIn("[error] send_release_notification.py:", proc.stderr)
            self.assertNotIn("Traceback", proc.stderr)
            self.assertEqual(request_count["value"], 1)

